// BRICK Protocol - site router. Pages render in isolated <iframe srcdoc>.

const PAGES = {
  "launch": "<!doctype html>\n<html lang=\"en\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n<title>BRICK Protocol \u2014 Genesis Formation</title>\n<style>\n  :root{\n    --obsidian:#0A0D12; --panel:#0E131A; --panel2:#0c1118; --raise:#121922;\n    --parch:#ECE5D6; --parch-dim:#b8b2a4; --ash:#7e8794; --faint:#4a525d;\n    --gold:#E3A93E; --gold-hi:#F6DC9A; --gold-lo:#B9822B;\n    --brick:#E8572A;\n    --line:rgba(227,169,62,.16); --line-soft:rgba(236,229,214,.07);\n    --mono:'Courier New',ui-monospace,Menlo,Consolas,monospace;\n    --sans:system-ui,-apple-system,'Segoe UI',Helvetica,Arial,sans-serif;\n    --black:'Arial Black','Helvetica Neue',Helvetica,Arial,sans-serif;\n    --serif:Georgia,'Times New Roman',serif;\n  }\n  *,*::before,*::after{margin:0;padding:0;box-sizing:border-box}\n  html{scroll-behavior:smooth}\n  body{\n    background:\n      radial-gradient(1100px 700px at 50% -260px, rgba(227,169,62,.10), transparent 60%),\n      radial-gradient(900px 520px at 100% 120%, rgba(232,87,42,.06), transparent 55%),\n      var(--obsidian);\n    color:var(--parch);font-family:var(--sans);font-size:16px;line-height:1.7;-webkit-font-smoothing:antialiased;\n    overflow-x:hidden;\n  }\n  .wrap{max-width:1080px;margin:0 auto;padding:0 28px}\n  a{color:inherit;text-decoration:none}\n  .mono{font-family:var(--mono)}\n  .o{color:var(--gold)}\n\n  /* brick course divider */\n  .course{height:7px;margin:0;\n    background:\n      repeating-linear-gradient(90deg, var(--gold-lo) 0 16px, transparent 16px 19px),\n      repeating-linear-gradient(90deg, transparent 0 8px, var(--gold) 8px 24px, transparent 24px 27px);\n    opacity:.20}\n\n  /* ===== NAV ===== */\n  nav.top{position:sticky;top:0;z-index:50;backdrop-filter:blur(10px);\n    background:linear-gradient(180deg,rgba(10,13,18,.92),rgba(10,13,18,.72));\n    border-bottom:1px solid var(--line)}\n  nav.top .wrap{display:flex;align-items:center;justify-content:space-between;height:62px}\n  .brand{font-family:var(--black);font-weight:900;letter-spacing:-1px;font-size:21px}\n  .brand .foil{background:linear-gradient(94deg,var(--gold-lo),var(--gold-hi) 45%,var(--gold-lo));-webkit-background-clip:text;background-clip:text;-webkit-text-fill-color:transparent}\n  .brand span.l{color:var(--ash);font-family:var(--mono);font-weight:400;font-size:11px;letter-spacing:.28em;margin-left:10px;text-transform:uppercase}\n  .navlinks{display:flex;gap:26px;align-items:center;font-family:var(--mono);font-size:12px;letter-spacing:.12em;text-transform:uppercase;color:var(--parch-dim)}\n  .navlinks a:hover{color:var(--gold)}\n  .navlinks .live{display:inline-flex;align-items:center;gap:8px;color:var(--gold);border:1px solid var(--line);border-radius:2px;padding:7px 12px}\n  .navlinks .live::before{content:\"\";width:7px;height:7px;border-radius:50%;background:var(--gold);box-shadow:0 0 0 0 rgba(227,169,62,.6);animation:pulse 2s infinite}\n  @keyframes pulse{0%{box-shadow:0 0 0 0 rgba(227,169,62,.5)}70%{box-shadow:0 0 0 7px rgba(227,169,62,0)}100%{box-shadow:0 0 0 0 rgba(227,169,62,0)}}\n  @media(max-width:760px){.navlinks a:not(.live){display:none}}\n\n  /* ===== HERO ===== */\n  .hero{padding:74px 0 64px}\n  .hero .wrap{display:grid;grid-template-columns:1.05fr .95fr;gap:56px;align-items:center}\n  .kicker{font-family:var(--mono);font-size:11px;letter-spacing:.4em;text-transform:uppercase;color:var(--ash)}\n  .hero h1{font-family:var(--black);font-weight:900;font-size:clamp(40px,6.6vw,72px);line-height:.96;letter-spacing:-2.5px;margin:18px 0 0}\n  .hero h1 .g{color:var(--gold)}\n  .hero .sub{font-family:var(--serif);font-style:italic;color:var(--parch-dim);font-size:clamp(17px,2.4vw,21px);line-height:1.45;max-width:520px;margin:22px 0 0}\n  .cta-row{display:flex;gap:14px;flex-wrap:wrap;margin-top:34px}\n  .btn{font-family:var(--mono);font-size:13px;letter-spacing:.1em;text-transform:uppercase;padding:15px 26px;border-radius:2px;border:1px solid var(--line);transition:.18s;display:inline-flex;align-items:center;gap:9px}\n  .btn.primary{background:linear-gradient(145deg,var(--gold-hi),var(--gold-lo));color:#1a1206;border-color:transparent;font-weight:700;box-shadow:0 8px 30px -10px rgba(227,169,62,.5)}\n  .btn.primary:hover{transform:translateY(-2px);box-shadow:0 14px 38px -10px rgba(227,169,62,.6)}\n  .btn.ghost{color:var(--parch)}\n  .btn.ghost:hover{border-color:var(--gold);color:var(--gold)}\n  .statstrip{display:flex;gap:30px;margin-top:40px;flex-wrap:wrap}\n  .statstrip .s .v{font-family:var(--black);font-size:24px;color:var(--gold);letter-spacing:-.5px}\n  .statstrip .s .k{font-family:var(--mono);font-size:10px;letter-spacing:.18em;text-transform:uppercase;color:var(--ash);margin-top:2px}\n\n  /* hero gem */\n  .gemstage{display:flex;flex-direction:column;align-items:center;gap:20px}\n  .pedestal{position:relative;padding:30px;border:1px solid var(--line);border-radius:4px;\n    background:radial-gradient(420px 320px at 50% 20%,rgba(227,169,62,.10),transparent 70%),var(--panel)}\n  .pedestal::after{content:\"\";position:absolute;inset:0;border-radius:4px;pointer-events:none;\n    background:linear-gradient(115deg,transparent 30%,rgba(246,220,154,.10) 47%,transparent 60%);\n    background-size:280% 100%;animation:sheen 6s ease-in-out infinite}\n  @keyframes sheen{0%,100%{background-position:140% 0}50%{background-position:-40% 0}}\n  .pgrid{display:grid;gap:2px}\n  .pc{width:13px;height:13px;border-radius:1px;background:transparent}\n  .pc.on{background:linear-gradient(145deg,var(--gold-hi),var(--gold-lo));box-shadow:inset 0 -1px 0 rgba(0,0,0,.4),inset 0 1px 0 rgba(255,255,255,.22)}\n  .gemcap{font-family:var(--mono);font-size:11px;letter-spacing:.16em;text-transform:uppercase;color:var(--ash);text-align:center}\n  .stonestrip{display:flex;gap:5px;flex-wrap:wrap;justify-content:center;max-width:300px}\n  .stone{width:17px;height:17px;border-radius:2px;box-shadow:inset 0 -2px 0 rgba(0,0,0,.35),inset 0 1px 0 rgba(255,255,255,.25)}\n  @media(max-width:880px){.hero .wrap{grid-template-columns:1fr;gap:44px}.gemstage{order:-1}}\n\n  /* ===== SECTION SHELL ===== */\n  section.blk{padding:72px 0}\n  .eyebrow{font-family:var(--mono);font-size:11px;letter-spacing:.36em;text-transform:uppercase;color:var(--gold);font-weight:700}\n  h2{font-family:var(--black);font-weight:900;font-size:clamp(28px,4.6vw,42px);letter-spacing:-1.3px;line-height:1.02;margin:12px 0 0;color:var(--parch)}\n  h2 .o{color:var(--gold)}\n  .lead{color:var(--parch-dim);max-width:640px;margin-top:16px;font-size:17px}\n\n  /* ===== GENESIS CARD ===== */\n  .genesis{background:linear-gradient(180deg,var(--panel),var(--panel2));border:1px solid var(--line);border-radius:6px;overflow:hidden;margin-top:30px}\n  .genesis .top{display:grid;grid-template-columns:1.2fr 1fr;gap:0}\n  .gx{padding:38px}\n  .gx.l{border-right:1px solid var(--line)}\n  .gx .lab{font-family:var(--mono);font-size:10px;letter-spacing:.2em;text-transform:uppercase;color:var(--ash)}\n  .price{font-family:var(--black);font-size:clamp(30px,4vw,40px);color:var(--gold);letter-spacing:-1px;margin:6px 0 2px}\n  .price small{font-family:var(--mono);font-size:13px;color:var(--parch-dim);letter-spacing:0;font-weight:400}\n  .getline{font-family:var(--mono);font-size:13px;color:var(--parch);margin-top:14px}\n  .getline b{color:var(--gold)}\n  .glist{list-style:none;margin-top:20px;display:grid;gap:10px}\n  .glist li{font-family:var(--mono);font-size:12.5px;color:var(--parch-dim);display:flex;gap:10px;align-items:flex-start}\n  .glist li::before{content:\"\u25c6\";color:var(--gold);font-size:10px;margin-top:3px}\n  .progwrap{margin-top:6px}\n  .progmeta{display:flex;justify-content:space-between;font-family:var(--mono);font-size:11px;color:var(--ash);letter-spacing:.1em;text-transform:uppercase;margin-bottom:10px}\n  .progmeta .c{color:var(--gold)}\n  .track{height:10px;border-radius:6px;background:var(--raise);border:1px solid var(--line);overflow:hidden}\n  .fill{height:100%;width:0;border-radius:6px;background:linear-gradient(90deg,var(--gold-lo),var(--gold-hi));transition:width 1.4s cubic-bezier(.2,.8,.2,1)}\n  .gx.r .btn.primary{width:100%;justify-content:center;margin-top:26px}\n  .gnote{font-family:var(--mono);font-size:10.5px;color:var(--ash);text-align:center;margin-top:14px;line-height:1.7}\n  .gbar{display:flex;flex-wrap:wrap;gap:8px 26px;padding:18px 38px;border-top:1px solid var(--line);font-family:var(--mono);font-size:11px;color:var(--ash);letter-spacing:.1em;text-transform:uppercase}\n  .gbar b{color:var(--gold);font-weight:400}\n  @media(max-width:760px){.genesis .top{grid-template-columns:1fr}.gx.l{border-right:none;border-bottom:1px solid var(--line)}}\n\n  /* ===== STEPS ===== */\n  .steps{display:grid;grid-template-columns:repeat(4,1fr);gap:18px;margin-top:34px}\n  .step{background:var(--panel);border:1px solid var(--line);border-radius:5px;padding:24px;position:relative;transition:.2s}\n  .step:hover{border-color:rgba(227,169,62,.4);transform:translateY(-3px)}\n  .step .n{font-family:var(--black);font-size:13px;color:#1a1206;background:linear-gradient(145deg,var(--gold-hi),var(--gold-lo));width:30px;height:30px;border-radius:3px;display:flex;align-items:center;justify-content:center}\n  .step h4{font-family:var(--sans);font-weight:800;font-size:16px;margin:16px 0 8px;color:var(--parch)}\n  .step p{font-size:13.5px;color:var(--parch-dim);line-height:1.55}\n  @media(max-width:880px){.steps{grid-template-columns:repeat(2,1fr)}}\n  @media(max-width:480px){.steps{grid-template-columns:1fr}}\n\n  /* ===== STONES LADDER ===== */\n  .ladder{margin-top:30px;border:1px solid var(--line);border-radius:5px;overflow:hidden}\n  .lrow{display:grid;grid-template-columns:30px 1fr 92px 64px;align-items:center;gap:16px;padding:11px 18px;border-bottom:1px solid var(--line-soft);font-family:var(--mono);font-size:12.5px}\n  .lrow:last-child{border-bottom:none}\n  .lrow:hover{background:rgba(227,169,62,.04)}\n  .lrow .sw{width:18px;height:18px;border-radius:3px;box-shadow:inset 0 -2px 0 rgba(0,0,0,.35),inset 0 1px 0 rgba(255,255,255,.25)}\n  .lrow .nm{color:var(--parch)}\n  .lrow .ti{color:var(--ash);text-align:right;font-size:11px;letter-spacing:.06em}\n  .lrow .sh{color:var(--gold);text-align:right}\n  .ladhead{background:rgba(227,169,62,.05);color:var(--gold);text-transform:uppercase;font-size:10px;letter-spacing:.13em}\n  .ladhead .nm,.ladhead .ti,.ladhead .sh{color:var(--gold)}\n\n  /* ===== MASTER CLASSES ===== */\n  .masters{display:grid;grid-template-columns:1fr 1fr;gap:18px;margin-top:32px}\n  .mcard{border:1px solid var(--line);border-radius:6px;padding:30px;background:linear-gradient(180deg,var(--panel),var(--panel2));position:relative;overflow:hidden}\n  .mcard .rank{position:absolute;top:18px;right:20px;font-family:var(--mono);font-size:10px;letter-spacing:.2em;color:var(--ash);text-transform:uppercase}\n  .mcard h3{font-family:var(--black);font-size:23px;letter-spacing:-.6px;color:var(--gold);margin-bottom:10px}\n  .mcard p{font-size:14px;color:var(--parch-dim);line-height:1.55}\n  .mchip{display:inline-block;margin-top:16px;font-family:var(--mono);font-size:10px;letter-spacing:.14em;text-transform:uppercase;color:var(--brick);border:1px solid rgba(232,87,42,.3);border-radius:2px;padding:5px 10px}\n  @media(max-width:680px){.masters{grid-template-columns:1fr}}\n\n  /* ===== PILLARS ===== */\n  .pillars{display:grid;grid-template-columns:repeat(4,1fr);gap:0;margin-top:32px;border:1px solid var(--line);border-radius:5px;overflow:hidden}\n  .pillar{padding:28px;border-right:1px solid var(--line)}\n  .pillar:last-child{border-right:none}\n  .pillar .ic{font-family:var(--black);color:var(--gold);font-size:22px}\n  .pillar h4{font-size:15px;font-weight:800;margin:14px 0 7px}\n  .pillar p{font-size:13px;color:var(--parch-dim);line-height:1.5}\n  @media(max-width:880px){.pillars{grid-template-columns:1fr 1fr}.pillar:nth-child(2){border-right:none}.pillar:nth-child(1),.pillar:nth-child(2){border-bottom:1px solid var(--line)}}\n  @media(max-width:480px){.pillars{grid-template-columns:1fr}.pillar{border-right:none;border-bottom:1px solid var(--line)}.pillar:last-child{border-bottom:none}}\n\n  /* ===== FAQ ===== */\n  .faq{margin-top:30px;max-width:780px}\n  details{border-bottom:1px solid var(--line);padding:6px 0}\n  summary{cursor:pointer;list-style:none;padding:16px 0;font-weight:700;font-size:16px;display:flex;justify-content:space-between;gap:16px;color:var(--parch)}\n  summary::-webkit-details-marker{display:none}\n  summary::after{content:\"+\";color:var(--gold);font-family:var(--mono);font-size:20px;transition:.2s}\n  details[open] summary::after{transform:rotate(45deg)}\n  details p{padding:0 0 18px;color:var(--parch-dim);font-size:14.5px;max-width:680px}\n\n  /* ===== FOOTER ===== */\n  footer{border-top:1px solid var(--line);padding:46px 0 60px;margin-top:20px}\n  .foot-grid{display:flex;justify-content:space-between;gap:30px;flex-wrap:wrap;align-items:flex-start}\n  .foot-links{display:flex;gap:24px;font-family:var(--mono);font-size:12px;letter-spacing:.1em;text-transform:uppercase;color:var(--parch-dim)}\n  .foot-links a:hover{color:var(--gold)}\n  .addr{font-family:var(--mono);font-size:11px;color:var(--ash);margin-top:18px}\n  .addr b{color:var(--gold)}\n  .addr code{color:var(--parch-dim);border:1px solid var(--line);border-radius:2px;padding:3px 8px;display:inline-block;margin-top:6px}\n  .disc{font-family:var(--mono);font-size:10.5px;color:var(--faint);line-height:1.8;margin-top:26px;max-width:880px}\n  .disc .em{color:var(--gold)}\n\n  /* reveal */\n  .rv{opacity:0;transform:translateY(18px);transition:opacity .7s ease,transform .7s ease}\n  .rv.in{opacity:1;transform:none}\n  @media(prefers-reduced-motion:reduce){.rv{opacity:1;transform:none;transition:none}.pedestal::after,.navlinks .live::before{animation:none}}\n\n  /* ===== build \u2192 3D faceted gem ===== */\n  .gemmorph{position:relative;display:grid;place-items:center;width:240px;height:240px;perspective:780px}\n  .pixgem,.facetgem{grid-area:1/1}\n  .pixgem{transition:opacity .7s ease,transform .7s ease}\n  .pixgem .pc.on{opacity:0;animation:drop .46s ease forwards}\n  @keyframes drop{0%{opacity:0;transform:translateY(-11px) scale(.25)}100%{opacity:1;transform:none}}\n  .facetgem{width:188px;height:206px;opacity:0;transform:rotateY(-14deg) scale(.6);transform-style:preserve-3d;\n    filter:drop-shadow(0 20px 24px rgba(0,0,0,.5)) drop-shadow(0 0 18px rgba(227,169,62,.28))}\n  .facetgem .edge polygon{stroke:rgba(40,26,6,.5);stroke-width:.6;stroke-linejoin:round}\n  .gemmorph.done .pixgem{opacity:0;transform:scale(1.16) translateY(-7px)}\n  .gemmorph.done .facetgem{opacity:1;animation:gemin .9s cubic-bezier(.2,.9,.2,1) forwards, idle 7.5s ease-in-out 1s infinite}\n  @keyframes gemin{0%{opacity:0;transform:rotateY(-32deg) scale(.55)}100%{opacity:1;transform:rotateY(-14deg) scale(1)}}\n  @keyframes idle{0%,100%{transform:rotateY(-14deg) rotateX(6deg) translateY(0)}50%{transform:rotateY(14deg) rotateX(-3deg) translateY(-7px)}}\n  .sparkle{position:absolute;top:60px;left:132px;width:24px;height:24px;pointer-events:none;opacity:0}\n  .gemmorph.done .sparkle{animation:tw 3.4s ease-in-out 1.5s infinite}\n  @keyframes tw{0%,100%{opacity:0;transform:scale(.3) rotate(0)}45%{opacity:.95;transform:scale(1) rotate(40deg)}62%{opacity:.25;transform:scale(.6) rotate(55deg)}}\n  @media(prefers-reduced-motion:reduce){\n    .pixgem{display:none}\n    .facetgem{opacity:1;transform:rotateY(-10deg) scale(1);animation:none}\n    .sparkle{display:none}\n  }\n</style>\n<style>nav.top{display:none!important}</style>\n</head>\n<body>\n\n<nav class=\"top\">\n  <div class=\"wrap\">\n    <div class=\"brand\"><span class=\"foil\">BRICK</span><span class=\"l\">Protocol</span></div>\n    <div class=\"navlinks\">\n      <a href=\"#\" onclick=\"parent.postMessage({brickNav:'whitepaper'},'*');return false;\">Whitepaper</a>\n      <a href=\"#how\">How it works</a>\n      <a href=\"#stones\">Stones</a>\n      <a href=\"#\" onclick=\"parent.postMessage({brickNav:'genesis'},'*');return false;\" class=\"live\">Genesis Live</a>\n    </div>\n  </div>\n</nav>\n\n<!-- HERO -->\n<header class=\"hero\">\n  <div class=\"wrap\">\n    <div class=\"rv in\">\n      <div class=\"kicker\">Hacash \u00b7 Proof of Building</div>\n      <h1>HACD is the gold.<br><span class=\"g\">BRICK is the craft.</span></h1>\n      <p class=\"sub\">One million colored stones, laid down once. Set them into works modeled on the diamond you hold \u2014 and craft scarcity by hand.</p>\n      <div class=\"cta-row\">\n        <a href=\"#\" onclick=\"parent.postMessage({brickNav:'genesis'},'*');return false;\" class=\"btn primary\">Join Genesis \u2192</a>\n        <a href=\"#\" onclick=\"parent.postMessage({brickNav:'whitepaper'},'*');return false;\" class=\"btn ghost\">Read Whitepaper</a>\n      </div>\n      <div class=\"statstrip\">\n        <div class=\"s\"><div class=\"v\">1,000,000</div><div class=\"k\">Fixed Supply</div></div>\n        <div class=\"s\"><div class=\"v\">500</div><div class=\"k\">Genesis Slots</div></div>\n        <div class=\"s\"><div class=\"v\">0%</div><div class=\"k\">Team Allocation</div></div>\n      </div>\n    </div>\n    <div class=\"gemstage rv in\">\n      <div class=\"pedestal\">\n        <div class=\"gemmorph\" id=\"gemmorph\">\n          <div class=\"pgrid pixgem\" id=\"gem\"></div>\n          <svg class=\"facetgem\" viewBox=\"0 0 200 220\" aria-label=\"Worked diamond\">\n            <defs>\n              <linearGradient id=\"gT\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\"><stop offset=\"0\" stop-color=\"#FBEFCB\"/><stop offset=\"1\" stop-color=\"#E3A93E\"/></linearGradient>\n              <linearGradient id=\"gB\" x1=\"0\" y1=\"0\" x2=\"1\" y2=\"1\"><stop offset=\"0\" stop-color=\"#F6DC9A\"/><stop offset=\"1\" stop-color=\"#C9912F\"/></linearGradient>\n              <linearGradient id=\"gM\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\"><stop offset=\"0\" stop-color=\"#E3A93E\"/><stop offset=\"1\" stop-color=\"#9A6E22\"/></linearGradient>\n              <linearGradient id=\"gD\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\"><stop offset=\"0\" stop-color=\"#B9822B\"/><stop offset=\"1\" stop-color=\"#6B4A15\"/></linearGradient>\n            </defs>\n            <g class=\"edge\">\n              <polygon points=\"70,22 130,22 140,72 60,72\" fill=\"url(#gT)\"/>\n              <polygon points=\"70,22 60,72 24,72\" fill=\"url(#gM)\"/>\n              <polygon points=\"130,22 176,72 140,72\" fill=\"url(#gB)\"/>\n              <polygon points=\"24,72 60,72 100,208\" fill=\"url(#gD)\"/>\n              <polygon points=\"60,72 100,72 100,208\" fill=\"url(#gB)\"/>\n              <polygon points=\"100,72 140,72 100,208\" fill=\"url(#gM)\"/>\n              <polygon points=\"140,72 176,72 100,208\" fill=\"url(#gD)\"/>\n              <polygon points=\"88,72 112,72 100,208\" fill=\"#FBEFCB\" opacity=\".5\"/>\n            </g>\n            <polygon points=\"78,28 116,28 110,40 84,40\" fill=\"#fff\" opacity=\".32\"/>\n            <line x1=\"24\" y1=\"72\" x2=\"176\" y2=\"72\" stroke=\"rgba(255,243,205,.45)\" stroke-width=\"1\"/>\n          </svg>\n          <svg class=\"sparkle\" viewBox=\"0 0 24 24\"><path d=\"M12 0 L14 10 L24 12 L14 14 L12 24 L10 14 L0 12 L10 10 Z\" fill=\"#fff\"/></svg>\n        </div>\n      </div>\n      <div class=\"stonestrip\" id=\"strip\"></div>\n      <div class=\"gemcap\">16 colors \u00b7 assigned by chance</div>\n    </div>\n  </div>\n</header>\n\n<div class=\"course\"></div>\n\n<!-- GENESIS -->\n<section class=\"blk\" id=\"genesis\">\n  <div class=\"wrap rv\">\n    <div class=\"eyebrow\">Genesis Formation</div>\n    <h2>Claim Your <span class=\"o\">Genesis Slot</span></h2>\n    <p class=\"lead\">Genesis lays down the entire BRICK supply at once. Every slot brings a diamond into your workshop and a starting stock of colored stones \u2014 their colors drawn by chance. No team, no private, no venture allocation. Fully open.</p>\n\n    <div class=\"genesis\">\n      <div class=\"top\">\n        <div class=\"gx l\">\n          <div class=\"lab\">Per Slot</div>\n          <div class=\"price\">1 HACD + 30 HAC <small>/ slot</small></div>\n          <div class=\"getline\">You receive <b>2,000 colored stones</b> \u2014 colors assigned by chance.</div>\n          <ul class=\"glist\">\n            <li>Fixed supply of 1,000,000 BRICK \u2014 no minting, ever</li>\n            <li>No team, private, or VC allocation</li>\n            <li>No vesting \u00b7 open participation</li>\n            <li>All 500 slots public</li>\n          </ul>\n        </div>\n        <div class=\"gx r\">\n          <div class=\"progwrap\">\n            <div class=\"progmeta\"><span>Slots claimed</span><span class=\"c\"><span id=\"claimed\">0</span> / 500</span></div>\n            <div class=\"track\"><div class=\"fill\" id=\"fill\"></div></div>\n          </div>\n          <a href=\"#\" class=\"btn primary\" id=\"mint\">Connect &amp; Mint</a>\n          <div class=\"gnote\">Genesis launches via HACD Labs Launchpad.<br>Participation is not an investment or guarantee of any kind.</div>\n        </div>\n      </div>\n      <div class=\"gbar\">\n        <span>Supply <b>1,000,000 \u00b7 Fixed</b></span>\n        <span>Per Slot <b>2,000 BRICK</b></span>\n        <span>Market <b>HAC \u00b7 2% Fee</b></span>\n        <span>Launch <b>HACD Labs</b></span>\n      </div>\n    </div>\n  </div>\n</section>\n\n<div class=\"course\"></div>\n\n<!-- HOW -->\n<section class=\"blk\" id=\"how\">\n  <div class=\"wrap rv\">\n    <div class=\"eyebrow\">How It Works</div>\n    <h2>Acquire. Build. <span class=\"o\">Craft Scarcity.</span></h2>\n    <div class=\"steps\">\n      <div class=\"step\"><div class=\"n\">1</div><h4>Acquire stones</h4><p>Buy at Genesis, or collect on the market in HAC \u2014 color by color. Supply is fixed at one million.</p></div>\n      <div class=\"step\"><div class=\"n\">2</div><h4>Build on your HACD</h4><p>Pick a diamond you hold as your canvas. Its colors are the rarity you aim for. The HACD is never touched.</p></div>\n      <div class=\"step\"><div class=\"n\">3</div><h4>Complete a work</h4><p>Set stones into a native design. Finish it and a worked diamond is recorded inside BRICK \u2014 modeled on your gold.</p></div>\n      <div class=\"step\"><div class=\"n\">4</div><h4>Keep, list, or dismantle</h4><p>Hold the piece, sell it in HAC, or break it back into stones to build again. Completion may even strike a HAC drop.</p></div>\n    </div>\n  </div>\n</section>\n\n<div class=\"course\"></div>\n\n<!-- STONES -->\n<section class=\"blk\" id=\"stones\">\n  <div class=\"wrap rv\">\n    <div class=\"eyebrow\">The Stones</div>\n    <h2>Sixteen Colors, <span class=\"o\">One Rarity Ladder</span></h2>\n    <p class=\"lead\">The million stones split across 16 colors. Rarer colors were laid down in far smaller numbers \u2014 and because no more will ever be made, their scarcity is permanent. Mirroring a HACD that carries them is the hardest craft of all.</p>\n    <div class=\"ladder\" id=\"ladder\"></div>\n  </div>\n</section>\n\n<div class=\"course\"></div>\n\n<!-- RARITY -->\n<section class=\"blk\">\n  <div class=\"wrap rv\">\n    <div class=\"eyebrow\">Master Classes</div>\n    <h2>The Rarest Things <span class=\"o\">a Builder Can Make</span></h2>\n    <div class=\"masters\">\n      <div class=\"mcard\">\n        <div class=\"rank\">Rarest</div>\n        <h3>Signature</h3>\n        <p>A work whose colors replicate its HACD's own palette, stone for stone \u2014 an exact match to the gold it is modeled on.</p>\n        <span class=\"mchip\">Exact Palette</span>\n      </div>\n      <div class=\"mcard\">\n        <div class=\"rank\">Second Class</div>\n        <h3>Monochrome</h3>\n        <p>A work built entirely from a single color \u2014 pure, disciplined, and demanding of stones Genesis made scarce on purpose.</p>\n        <span class=\"mchip\">One Color</span>\n      </div>\n    </div>\n  </div>\n</section>\n\n<div class=\"course\"></div>\n\n<!-- WHY -->\n<section class=\"blk\">\n  <div class=\"wrap rv\">\n    <div class=\"eyebrow\">Why BRICK</div>\n    <h2>Value Is Built, <span class=\"o\">Never Printed</span></h2>\n    <div class=\"pillars\">\n      <div class=\"pillar\"><div class=\"ic\">\u221e</div><h4>Fixed forever</h4><p>1,000,000 stones, minted once at Genesis. No emission, no inflation, no second printing.</p></div>\n      <div class=\"pillar\"><div class=\"ic\">\u25c6</div><h4>Real scarcity</h4><p>Rare colors were laid down in tiny numbers. Price is set by builders, not by a faucet.</p></div>\n      <div class=\"pillar\"><div class=\"ic\">\u2b21</div><h4>HAC-native</h4><p>The whole market runs in HAC. Build, trade, and earn in the asset of the Hacash chain.</p></div>\n      <div class=\"pillar\"><div class=\"ic\">\u2666</div><h4>Your gold is safe</h4><p>Works are modeled on your HACD, never carved into it. The diamond stays pure gold.</p></div>\n    </div>\n  </div>\n</section>\n\n<div class=\"course\"></div>\n\n<!-- FAQ -->\n<section class=\"blk\">\n  <div class=\"wrap rv\">\n    <div class=\"eyebrow\">Questions</div>\n    <h2>Before You <span class=\"o\">Build</span></h2>\n    <div class=\"faq\">\n      <details open><summary>What do I get at Genesis?</summary><p>For 1 HACD + 30 HAC per slot, you receive 2,000 colored stones \u2014 your starting material. Their 16 colors are assigned by chance, following the rarity ladder. There are 500 slots, all public.</p></details>\n      <details><summary>Can I join after Genesis sells out?</summary><p>Yes. The entire supply is fixed and distributed at Genesis, but stones and finished works trade freely on the HAC market. Anyone can become a builder by collecting the stones they need, color by color.</p></details>\n      <details><summary>Is BRICK inflationary?</summary><p>No. Supply is permanently fixed at 1,000,000. No BRICK is ever minted after Genesis \u2014 there is no daily generation and no emission of any kind. Scarcity only deepens as stones are set into works.</p></details>\n      <details><summary>What happens to my HACD when I build?</summary><p>Nothing. A worked diamond is a creation recorded inside BRICK Protocol, modeled on your HACD's colors. Your real diamond on Hacash is never spent, altered, or locked \u2014 it stays pure gold.</p></details>\n      <details><summary>How does the protocol make money?</summary><p>A flat 2% commission on every market sale \u2014 a 100 HAC sale returns 2 HAC. That is the protocol's only revenue, and it funds the chance-based HAC drops that may reward a completed work.</p></details>\n    </div>\n  </div>\n</section>\n\n<!-- FOOTER -->\n<footer>\n  <div class=\"wrap\">\n    <div class=\"foot-grid\">\n      <div class=\"brand\"><span class=\"foil\">BRICK</span><span class=\"l\">Protocol</span></div>\n      <div class=\"foot-links\">\n        <a href=\"#\" onclick=\"parent.postMessage({brickNav:'whitepaper'},'*');return false;\">Whitepaper</a>\n        <a href=\"https://x.com/protocolbrick\" target=\"_blank\" rel=\"noreferrer\">X / Twitter</a>\n        <a href=\"https://t.me/protocolbrick\" target=\"_blank\" rel=\"noreferrer\">Telegram</a>\n        <a href=\"https://hacd.it/launchpad\" target=\"_blank\" rel=\"noreferrer\">HACD Labs</a>\n      </div>\n    </div>\n    <div class=\"addr\"><b>Genesis HAC receiving address</b><br><code>19UWYeDC4DnQQGJoXvykBGp1WUnVUtcUVu</code></div>\n    <div class=\"disc\">\n      <span class=\"em\">DISCLAIMER</span> \u2014 This page describes BRICK Protocol for informational purposes only. It is not investment advice, an offer, or a solicitation. BRICK is a fixed-supply utility asset for producing works; it is not a security, carries no claim or dividend, and the protocol makes no promise of profit, income, or return. Completion rewards are chance-based, variable, and never guaranteed. Participation in Genesis does not constitute an investment or guarantee of any kind. Features remain subject to development and implementation.<br><br>\n      BRICK Protocol \u00b7 Proof of Building Economy \u00b7 HACD Native \u00b7 Launch on HACD Labs \u00b7 0% Team Allocation\n    </div>\n  </div>\n</footer>\n\n<script>\n// ---- pixel gem (16x16) ----\nconst GEM=[\n\"0000111111110000\",\n\"0001111111111000\",\n\"0011111111111100\",\n\"0111111111111110\",\n\"1111111111111111\",\n\"0111111111111110\",\n\"0011111111111100\",\n\"0011111111111100\",\n\"0001111111111000\",\n\"0001111111111000\",\n\"0000111111110000\",\n\"0000011111100000\",\n\"0000011111100000\",\n\"0000001111000000\",\n\"0000000110000000\",\n\"0000000110000000\"];\n(function(){\n  const g=document.getElementById('gem');\n  g.style.gridTemplateColumns='repeat(16,13px)';\n  const reduce=window.matchMedia('(prefers-reduced-motion: reduce)').matches;\n  GEM.forEach((row,r)=>{[...row].forEach(ch=>{\n    const d=document.createElement('div');\n    d.className='pc'+(ch==='1'?' on':'');\n    if(ch==='1'&&!reduce){d.style.animationDelay=(r*52+Math.random()*40)+'ms';}\n    g.appendChild(d);\n  });});\n  if(!reduce){\n    const m=document.getElementById('gemmorph');\n    setTimeout(()=>m.classList.add('done'),1500);\n  }\n})();\n\n// ---- 16 colors (rarest -> common), shares sum to 100 ----\nconst COLORS=[\n [\"Ruby Red\",\"#E0303A\",\"Mythic\",\"2.0\"],\n [\"Emerald\",\"#2FB46A\",\"Mythic\",\"2.5\"],\n [\"Sapphire\",\"#2D6BE0\",\"Legendary\",\"3.0\"],\n [\"Violet\",\"#7A3FE0\",\"Legendary\",\"3.5\"],\n [\"Rose\",\"#E85FA8\",\"Epic\",\"4.0\"],\n [\"Amber\",\"#E8842A\",\"Epic\",\"4.5\"],\n [\"Cyan\",\"#2FC4CF\",\"Epic\",\"5.0\"],\n [\"Citrine\",\"#E8C53A\",\"Rare\",\"5.5\"],\n [\"Teal\",\"#2E9E8F\",\"Rare\",\"6.5\"],\n [\"Magenta\",\"#C24FD1\",\"Rare\",\"7.0\"],\n [\"Lime\",\"#8FC73A\",\"Uncommon\",\"7.5\"],\n [\"Indigo\",\"#4256C8\",\"Uncommon\",\"8.0\"],\n [\"Slate\",\"#6E7A8A\",\"Common\",\"9.0\"],\n [\"Bronze\",\"#9A6A3A\",\"Common\",\"9.5\"],\n [\"Ash\",\"#9098A0\",\"Common\",\"10.0\"],\n [\"Clear\",\"#D8D2C4\",\"Common\",\"12.5\"]];\n\n// hero strip\n(function(){\n  const s=document.getElementById('strip');\n  COLORS.forEach(c=>{const d=document.createElement('div');d.className='stone';d.style.background=`linear-gradient(145deg,${c[1]},${shade(c[1],-30)})`;d.title=`${c[0]} \u00b7 ${c[3]}%`;s.appendChild(d);});\n})();\n\n// rarity ladder\n(function(){\n  const L=document.getElementById('ladder');\n  const head=document.createElement('div');head.className='lrow ladhead';\n  head.innerHTML=`<div></div><div class=\"nm\">Color</div><div class=\"ti\">Tier</div><div class=\"sh\">Share</div>`;\n  L.appendChild(head);\n  COLORS.forEach(c=>{\n    const r=document.createElement('div');r.className='lrow';\n    r.innerHTML=`<div class=\"sw\" style=\"background:linear-gradient(145deg,${c[1]},${shade(c[1],-30)})\"></div><div class=\"nm\">${c[0]}</div><div class=\"ti\">${c[2]}</div><div class=\"sh\">${c[3]}%</div>`;\n    L.appendChild(r);\n  });\n})();\n\nfunction shade(hex,p){const n=parseInt(hex.slice(1),16);let r=(n>>16)+p,g=((n>>8)&255)+p,b=(n&255)+p;r=Math.max(0,Math.min(255,r));g=Math.max(0,Math.min(255,g));b=Math.max(0,Math.min(255,b));return`rgb(${r},${g},${b})`;}\n\n// ---- genesis progress (team wires the real number) ----\nconst CLAIMED=0, TOTAL=500;\nwindow.addEventListener('load',()=>{\n  document.getElementById('claimed').textContent=CLAIMED;\n  setTimeout(()=>{document.getElementById('fill').style.width=(CLAIMED/TOTAL*100)+'%';},300);\n});\n\n// ---- scroll reveal ----\nconst io=new IntersectionObserver((es)=>{es.forEach(e=>{if(e.isIntersecting){e.target.classList.add('in');io.unobserve(e.target);}});},{threshold:.12});\ndocument.querySelectorAll('.rv:not(.in)').forEach(el=>io.observe(el));\n</script>\n</body>\n</html>\n",
  "whitepaper": "<!doctype html>\n<html lang=\"en\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n<title>BRICK Protocol \u2014 Whitepaper</title>\n<style>\n  :root{\n    --obsidian:#0A0D12; --panel:#0E131A; --panel2:#0c1118; --raise:#121922;\n    --parch:#ECE5D6; --parch-dim:#b8b2a4; --ash:#7e8794; --faint:#4a525d;\n    --gold:#E3A93E; --gold-hi:#F6DC9A; --gold-lo:#B9822B;\n    --brick:#E8572A;\n    --line:rgba(227,169,62,.16); --line-soft:rgba(236,229,214,.07);\n    --mono:'Courier New',ui-monospace,Menlo,Consolas,monospace;\n    --sans:system-ui,-apple-system,'Segoe UI',Helvetica,Arial,sans-serif;\n    --black:'Arial Black','Helvetica Neue',Helvetica,Arial,sans-serif;\n    --serif:Georgia,'Times New Roman',serif;\n  }\n  *,*::before,*::after{margin:0;padding:0;box-sizing:border-box}\n  html{scroll-behavior:smooth}\n  body{\n    background:\n      radial-gradient(1100px 700px at 50% -200px, rgba(227,169,62,.08), transparent 60%),\n      radial-gradient(900px 500px at 100% 100%, rgba(232,87,42,.05), transparent 55%),\n      var(--obsidian);\n    color:var(--parch);font-family:var(--sans);font-size:16px;line-height:1.7;-webkit-font-smoothing:antialiased;\n  }\n  .doc{max-width:780px;margin:0 auto;padding:0 30px 90px}\n\n  /* gold foil text */\n  .foil{\n    background:linear-gradient(96deg,#B9822B 0%,#F6DC9A 28%,#E3A93E 52%,#F6DC9A 74%,#C8902F 100%);\n    background-size:200% 100%;\n    -webkit-background-clip:text;background-clip:text;color:transparent;\n    animation:sheen 9s linear infinite;\n  }\n  @keyframes sheen{0%{background-position:0% 0}100%{background-position:200% 0}}\n  @media(prefers-reduced-motion:reduce){.foil{animation:none}}\n\n  .eyebrow{font-family:var(--mono);font-size:11px;letter-spacing:.36em;text-transform:uppercase;color:var(--gold);font-weight:700}\n  .num{font-family:var(--mono);color:var(--brick);font-size:11px;letter-spacing:.2em}\n\n  /* ---------- cover ---------- */\n  .cover{min-height:100vh;display:flex;flex-direction:column;justify-content:center;padding:60px 0 40px;position:relative}\n  .cover .kicker{font-family:var(--mono);font-size:11px;letter-spacing:.4em;text-transform:uppercase;color:var(--ash)}\n  .wordmark{font-family:var(--black);font-weight:900;font-size:clamp(64px,16vw,140px);letter-spacing:-4px;line-height:.82;margin:16px 0 0}\n  .wordmark .l2{color:var(--parch);display:block}\n  .tagline{font-family:var(--serif);font-style:italic;font-size:clamp(18px,3.5vw,26px);color:var(--parch-dim);margin-top:22px;max-width:560px;line-height:1.4}\n  .cover-emblem{margin:40px 0 10px}\n  .specledger{margin-top:30px;border-top:1px solid var(--line)}\n  .specledger .r{display:flex;justify-content:space-between;gap:18px;padding:12px 0;border-bottom:1px solid var(--line);font-family:var(--mono);font-size:12.5px}\n  .specledger .r .k{color:var(--ash);letter-spacing:.04em}\n  .specledger .r .v{color:var(--parch);text-align:right}\n  .specledger .r .v.g{color:var(--gold)}\n\n  /* ---------- brick course divider ---------- */\n  .course{height:9px;margin:60px 0;\n    background:\n      repeating-linear-gradient(90deg, var(--gold-lo) 0 16px, transparent 16px 19px),\n      repeating-linear-gradient(90deg, transparent 0 8px, var(--gold) 8px 24px, transparent 24px 27px);\n    -webkit-mask:linear-gradient(90deg,transparent,#000 12%,#000 88%,transparent);\n            mask:linear-gradient(90deg,transparent,#000 12%,#000 88%,transparent);\n    opacity:.6}\n\n  /* ---------- contents ---------- */\n  .toc{margin:40px 0}\n  .toc h3{font-family:var(--mono);font-size:11px;letter-spacing:.3em;text-transform:uppercase;color:var(--ash);margin-bottom:16px}\n  .toc a{display:flex;align-items:baseline;gap:14px;padding:9px 0;border-bottom:1px solid var(--line-soft);text-decoration:none;color:var(--parch);font-size:15px}\n  .toc a:hover{color:var(--gold)}\n  .toc a .tn{font-family:var(--mono);color:var(--brick);font-size:12px;min-width:26px}\n  .toc a .td{flex:1;border-bottom:1px dotted var(--faint);margin:0 4px;transform:translateY(-3px)}\n\n  /* ---------- sections ---------- */\n  section{padding-top:18px;margin-top:34px}\n  .shead{display:flex;align-items:center;gap:14px;margin-bottom:6px}\n  h2{font-family:var(--black);font-weight:900;font-size:clamp(28px,5vw,40px);letter-spacing:-1.2px;line-height:1.0;margin:8px 0 16px;color:var(--parch)}\n  h2 .o{color:var(--gold)}\n  p{color:var(--parch-dim);margin:14px 0}\n  p.lead{color:var(--parch);font-size:17px}\n  strong{color:var(--parch);font-weight:700}\n  em{color:var(--gold);font-style:normal}\n\n  .pull{font-family:var(--serif);font-style:italic;font-size:22px;line-height:1.45;color:var(--gold-hi);border-left:2px solid var(--gold);padding:6px 0 6px 22px;margin:24px 0}\n\n  .callout{border:1px solid var(--line);background:linear-gradient(180deg,var(--raise),var(--panel2));padding:16px 20px;margin:22px 0;color:var(--parch-dim);font-size:14.5px;border-radius:3px}\n  .callout .mono{font-family:var(--mono);color:var(--gold)}\n  .callout.brick{border-color:rgba(232,87,42,.3)}\n\n  ul{margin:14px 0;list-style:none}\n  ul li{color:var(--parch-dim);padding:7px 0 7px 22px;position:relative}\n  ul li::before{content:'';position:absolute;left:0;top:15px;width:9px;height:9px;\n    background:linear-gradient(145deg,var(--gold-hi),var(--gold-lo));box-shadow:inset 0 -1px 0 rgba(0,0,0,.4)}\n\n  table{width:100%;border-collapse:collapse;font-family:var(--mono);font-size:12.5px;margin:22px 0;border:1px solid var(--line)}\n  th,td{padding:11px 14px;text-align:right;border-bottom:1px solid var(--line-soft)}\n  th{color:var(--gold);font-size:10px;letter-spacing:.13em;text-transform:uppercase;font-weight:400;background:rgba(227,169,62,.05)}\n  th:first-child,td:first-child{text-align:left}\n  td{color:var(--parch-dim)} td:first-child{color:var(--parch)}\n  tr:last-child td{border-bottom:none}\n  td .o{color:var(--gold)} td .b{color:var(--brick)}\n  tr.tot td{background:rgba(227,169,62,.06);color:var(--parch);font-weight:700;border-top:1px solid var(--line)}\n  .sw{display:inline-block;width:11px;height:11px;border-radius:2px;vertical-align:middle;margin-right:9px;box-shadow:inset 0 0 0 1px rgba(0,0,0,.3)}\n\n  /* pixel art */\n  .pixwrap{display:flex;flex-wrap:wrap;gap:18px;margin:24px 0}\n  .pix{text-align:center}\n  .pgrid{display:grid;gap:1.5px;margin:0 auto 8px}\n  .pc{border-radius:1px}\n  .pc.on{background:linear-gradient(145deg,var(--gold-hi),var(--gold-lo));box-shadow:inset 0 -1px 0 rgba(0,0,0,.4),inset 0 1px 0 rgba(255,255,255,.22)}\n  .pc.off{background:rgba(236,229,214,.04)}\n  .pix .lbl{font-family:var(--mono);font-size:10.5px;color:var(--ash)}\n  .pix .lbl b{color:var(--parch);display:block;letter-spacing:.04em}\n\n  /* flow */\n  .flow{margin:24px 0;border:1px solid var(--line)}\n  .flow .step{display:flex;gap:16px;padding:15px 18px;border-bottom:1px solid var(--line-soft)}\n  .flow .step:last-child{border-bottom:none}\n  .flow .n{font-family:var(--black);font-size:16px;color:var(--gold);min-width:26px}\n  .flow .t{font-family:var(--mono);font-size:13px;color:var(--parch)}\n  .flow .t b{color:var(--gold);font-weight:700}\n  .flow .t span{color:var(--ash);display:block;margin-top:3px;font-size:12.5px;line-height:1.5}\n\n  /* allocation bar */\n  .allocbar{display:flex;height:30px;border:1px solid var(--line);margin:22px 0 10px;overflow:hidden}\n  .allocbar i{display:block;height:100%}\n  .alloclegend{display:flex;flex-wrap:wrap;gap:6px 20px;font-family:var(--mono);font-size:11px;color:var(--ash);margin-bottom:8px}\n  .alloclegend span{display:flex;align-items:center;gap:7px}\n  .alloclegend span::before{content:'';width:10px;height:10px;background:var(--c)}\n\n  .foot{margin-top:60px;padding-top:24px;border-top:1px solid var(--line);font-family:var(--mono);font-size:11px;color:var(--ash);line-height:1.9}\n  .foot .em{color:var(--gold)}\n  ::selection{background:rgba(227,169,62,.25);color:#fff}  /* ===== cover: build \u2192 3D faceted gem ===== */\n  .gemmorph{position:relative;display:grid;place-items:center;width:240px;height:240px;perspective:780px;margin:0 auto}\n  .pixgem,.facetgem{grid-area:1/1}\n  .pixgem{transition:opacity .7s ease,transform .7s ease}\n  .pixgem .pc.on{opacity:0;animation:drop .46s ease forwards}\n  @keyframes drop{0%{opacity:0;transform:translateY(-11px) scale(.25)}100%{opacity:1;transform:none}}\n  .facetgem{width:188px;height:206px;opacity:0;transform:rotateY(-14deg) scale(.6);transform-style:preserve-3d;\n    filter:drop-shadow(0 20px 24px rgba(0,0,0,.5)) drop-shadow(0 0 18px rgba(227,169,62,.28))}\n  .facetgem .edge polygon{stroke:rgba(40,26,6,.5);stroke-width:.6;stroke-linejoin:round}\n  .gemmorph.done .pixgem{opacity:0;transform:scale(1.16) translateY(-7px)}\n  .gemmorph.done .facetgem{opacity:1;animation:gemin .9s cubic-bezier(.2,.9,.2,1) forwards, idle 7.5s ease-in-out 1s infinite}\n  @keyframes gemin{0%{opacity:0;transform:rotateY(-32deg) scale(.55)}100%{opacity:1;transform:rotateY(-14deg) scale(1)}}\n  @keyframes idle{0%,100%{transform:rotateY(-14deg) rotateX(6deg) translateY(0)}50%{transform:rotateY(14deg) rotateX(-3deg) translateY(-7px)}}\n  .sparkle{position:absolute;top:52px;left:150px;width:24px;height:24px;pointer-events:none;opacity:0}\n  .gemmorph.done .sparkle{animation:tw 3.4s ease-in-out 1.5s infinite}\n  @keyframes tw{0%,100%{opacity:0;transform:scale(.3) rotate(0)}45%{opacity:.95;transform:scale(1) rotate(40deg)}62%{opacity:.25;transform:scale(.6) rotate(55deg)}}\n  @media(prefers-reduced-motion:reduce){\n    .pixgem{display:none}\n    .facetgem{opacity:1;transform:rotateY(-10deg) scale(1);animation:none}\n    .sparkle{display:none}\n  }\n  .pix canvas{display:block;margin:0 auto;transition:transform .22s ease}\n  .pix:hover canvas{transform:translateY(-3px) scale(1.05)}\n\n  .apshell{position:relative;width:100%;max-width:184px;margin:0 auto;aspect-ratio:1;border-radius:14px;padding:8px;overflow:hidden;\n    border:1px solid rgba(227,169,62,.14);\n    background:radial-gradient(circle at top left,rgba(255,255,255,.06),transparent 30%),radial-gradient(circle at bottom right,rgba(227,169,62,.12),transparent 34%),rgba(8,8,11,.92);\n    box-shadow:inset 0 1px 0 rgba(255,255,255,.05),0 14px 30px rgba(0,0,0,.3)}\n  .apgrid{display:grid;gap:2px;width:100%;height:100%;transform:perspective(1200px) rotateX(8deg) rotateY(-10deg);transform-origin:center}\n  .apc{aspect-ratio:1;border-radius:5px}\n  .apc.f{border:1px solid rgba(255,255,255,.10);\n    background:linear-gradient(180deg,rgba(255,255,255,.16),transparent 46%),linear-gradient(135deg,var(--bc,#E3A93E),rgba(28,20,8,.78));\n    box-shadow:inset 0 1px 0 rgba(255,255,255,.12),inset 0 -6px 10px rgba(0,0,0,.14),0 4px 10px rgba(0,0,0,.14)}\n</style>\n</head>\n<body>\n<div class=\"doc\">\n\n  <!-- COVER -->\n  <header class=\"cover\">\n    <div class=\"kicker\">Hacash \u00b7 Proof of Building Economy</div>\n    <h1 class=\"wordmark\"><span class=\"foil\">BRICK</span><span class=\"l2\">Protocol</span></h1>\n    <p class=\"tagline\">HACD is the gold. BRICK is the craft that works a diamond beside it \u2014 signed, scarce, and made by hand.</p>\n\n    <div class=\"cover-emblem\">\n      <div class=\"gemmorph\" id=\"gemmorph\">\n        <div class=\"pgrid pixgem\" id=\"gem\"></div>\n        <svg class=\"facetgem\" viewBox=\"0 0 200 220\" aria-label=\"Worked diamond\">\n          <defs>\n            <linearGradient id=\"gT\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\"><stop offset=\"0\" stop-color=\"#FBEFCB\"/><stop offset=\"1\" stop-color=\"#E3A93E\"/></linearGradient>\n            <linearGradient id=\"gB\" x1=\"0\" y1=\"0\" x2=\"1\" y2=\"1\"><stop offset=\"0\" stop-color=\"#F6DC9A\"/><stop offset=\"1\" stop-color=\"#C9912F\"/></linearGradient>\n            <linearGradient id=\"gM\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\"><stop offset=\"0\" stop-color=\"#E3A93E\"/><stop offset=\"1\" stop-color=\"#9A6E22\"/></linearGradient>\n            <linearGradient id=\"gD\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\"><stop offset=\"0\" stop-color=\"#B9822B\"/><stop offset=\"1\" stop-color=\"#6B4A15\"/></linearGradient>\n          </defs>\n          <g class=\"edge\">\n            <polygon points=\"70,22 130,22 140,72 60,72\" fill=\"url(#gT)\"/>\n            <polygon points=\"70,22 60,72 24,72\" fill=\"url(#gM)\"/>\n            <polygon points=\"130,22 176,72 140,72\" fill=\"url(#gB)\"/>\n            <polygon points=\"24,72 60,72 100,208\" fill=\"url(#gD)\"/>\n            <polygon points=\"60,72 100,72 100,208\" fill=\"url(#gB)\"/>\n            <polygon points=\"100,72 140,72 100,208\" fill=\"url(#gM)\"/>\n            <polygon points=\"140,72 176,72 100,208\" fill=\"url(#gD)\"/>\n            <polygon points=\"88,72 112,72 100,208\" fill=\"#FBEFCB\" opacity=\".5\"/>\n          </g>\n          <polygon points=\"78,28 116,28 110,40 84,40\" fill=\"#fff\" opacity=\".32\"/>\n          <line x1=\"24\" y1=\"72\" x2=\"176\" y2=\"72\" stroke=\"rgba(255,243,205,.45)\" stroke-width=\"1\"/>\n        </svg>\n        <svg class=\"sparkle\" viewBox=\"0 0 24 24\"><path d=\"M12 0 L14 10 L24 12 L14 14 L12 24 L10 14 L0 12 L10 10 Z\" fill=\"#fff\"/></svg>\n      </div>\n    </div>\n\n    <div class=\"specledger\">\n      <div class=\"r\"><span class=\"k\">Asset</span><span class=\"v\">BRICK \u2014 Fixed-Supply Colored Stone</span></div>\n      <div class=\"r\"><span class=\"k\">Core Concept</span><span class=\"v\">Proof of Building</span></div>\n      <div class=\"r\"><span class=\"k\">Native Ecosystem</span><span class=\"v\">Hacash \u2014 HACD Stack Asset</span></div>\n      <div class=\"r\"><span class=\"k\">Total Supply</span><span class=\"v g\">1,000,000 \u00b7 Fixed</span></div>\n      <div class=\"r\"><span class=\"k\">Market</span><span class=\"v\">HAC \u00b7 2% Fee</span></div>\n      <div class=\"r\"><span class=\"k\">Genesis</span><span class=\"v\">500 slots \u00b7 1 HACD + 30 HAC</span></div>\n      <div class=\"r\"><span class=\"k\">Team Allocation</span><span class=\"v g\">None</span></div>\n    </div>\n  </header>\n\n  <!-- CONTENTS -->\n  <nav class=\"toc\">\n    <h3>Contents</h3>\n    <a href=\"#s1\"><span class=\"tn\">01</span>A Scarcity-Driven Craft Economy<span class=\"td\"></span></a>\n    <a href=\"#s2\"><span class=\"tn\">02</span>The Gold &amp; the Craft<span class=\"td\"></span></a>\n    <a href=\"#s3\"><span class=\"tn\">03</span>BRICK \u2014 One Million Colored Stones<span class=\"td\"></span></a>\n    <a href=\"#s4\"><span class=\"tn\">04</span>Sixteen Colors, One Ladder<span class=\"td\"></span></a>\n    <a href=\"#s5\"><span class=\"tn\">05</span>The Canvas \u2014 Build on Your HACD<span class=\"td\"></span></a>\n    <a href=\"#s6\"><span class=\"tn\">06</span>Building &amp; Rarity<span class=\"td\"></span></a>\n    <a href=\"#s7\"><span class=\"tn\">07</span>Native Catalog \u2014 Works<span class=\"td\"></span></a>\n    <a href=\"#s8\"><span class=\"tn\">08</span>Completion &amp; the HAC Drop<span class=\"td\"></span></a>\n    <a href=\"#s9\"><span class=\"tn\">09</span>Keep, List, or Dismantle<span class=\"td\"></span></a>\n    <a href=\"#s10\"><span class=\"tn\">10</span>The Market<span class=\"td\"></span></a>\n    <a href=\"#s11\"><span class=\"tn\">11</span>The Closed Loop<span class=\"td\"></span></a>\n    <a href=\"#s12\"><span class=\"tn\">12</span>Genesis Formation<span class=\"td\"></span></a>\n  </nav>\n\n  <div class=\"course\"></div>\n\n  <section id=\"s1\">\n    <div class=\"shead\"><span class=\"eyebrow\">Overview</span></div>\n    <h2>A Scarcity-Driven <span class=\"o\">Craft Economy</span></h2>\n    <p class=\"lead\">BRICK is a scarcity-driven craft economy on Hacash. A fixed pool of one million colored stones is laid down once, at Genesis, and never grows again. Builders take those stones and set them, one by one, into works modeled on the HACD they hold \u2014 turning raw color into crafted, ownable pieces.</p>\n    <p>Value is never printed here; it is built. A finished work is not a token handed out for waiting \u2014 it is an object of craft whose worth comes from its scarcity, the colors it carries, and the patience it took to assemble. The protocol does not earn for you. It gives you a million stones, a canvas of gold, and a place to build.</p>\n  </section>\n\n  <div class=\"course\"></div>\n\n  <section id=\"s2\">\n    <div class=\"shead\"><span class=\"eyebrow\">Core Thesis</span></div>\n    <h2>The Gold <span class=\"o\">&amp; the Craft</span></h2>\n    <p class=\"lead\">HACD is the gold of the Hacash ecosystem \u2014 scarce, liquid, a store of value. BRICK does not touch the HACD itself. Instead, BRICK lets you <strong>work a diamond modeled on your HACD</strong>: a crafted, colored creation recorded inside BRICK Protocol's own system.</p>\n    <p>Your real HACD on Hacash stays exactly as it is \u2014 an untouched store of value. The worked diamond is remembered within BRICK and can be recalled and displayed at any time, but it is never written onto the Hacash chain. It is a creation of the protocol, modeled on your gold, not an inscription upon it.</p>\n    <div class=\"pull\">The gold is never altered; the craft lives beside it. A bare HACD is an ingot \u2014 a worked diamond is a piece shaped by hand, color, and patience.</div>\n  </section>\n\n  <div class=\"course\"></div>\n\n  <section id=\"s3\">\n    <div class=\"shead\"><span class=\"eyebrow\">The Asset</span></div>\n    <h2>One Million <span class=\"o\">Colored Stones</span></h2>\n    <p class=\"lead\">BRICK is a fixed-supply asset: exactly <strong>1,000,000 stones</strong>, laid down in full at Genesis. No BRICK is ever minted afterward \u2014 there is no minting, no emission, and no inflation of any kind.</p>\n    <p>Every stone carries a color. At Genesis, each of the million stones is assigned one of sixteen colors <strong>entirely by chance</strong>, following the rarity ladder. A stone is the building material itself \u2014 there is no separate \"fuel\" to unlock; the colored stone is what you set into a work. Stones are individually ownable and transferable: you may hold them, build with them, or list them on the market in HAC.</p>\n    <div class=\"callout brick\"><strong>BRICK is the fixed-supply HACD Stack Asset. Each BRICK is a colored stone \u2014 building material and asset are one and the same.</strong> Supply is permanently fixed at 1,000,000; colors are assigned once, at Genesis, by chance, and never created again.</div>\n  </section>\n\n  <div class=\"course\"></div>\n\n  <section id=\"s4\">\n    <div class=\"shead\"><span class=\"eyebrow\">The Stone System</span></div>\n    <h2>Sixteen Colors, <span class=\"o\">One Rarity Ladder</span></h2>\n    <p>The million stones are split across <strong>16 colors</strong>, and that split is the foundation of the whole economy. Rarer colors were laid down in far smaller numbers at Genesis \u2014 and because no more will ever be made, their scarcity is permanent. The colors are not cosmetic: each carries an economic weight that sets the standing of any work it goes into, and every stone's color stays visible in the finished piece.</p>\n    <p>Rarity follows the order of colored-gemstone scarcity. The rarer the color, the smaller its share of the Genesis pool:</p>\n    <table>\n      <thead><tr><th>Color</th><th>Tier</th><th>Genesis Share</th></tr></thead>\n      <tbody id=\"colortable\"></tbody>\n    </table>\n    <div class=\"callout\">Rarity is resemblance. The closer a work's colors come to the palette of the HACD it is modeled on, the rarer it is \u2014 and because rare colors were laid down so seldom, mirroring a HACD that carries them is the hardest achievement of all.</div>\n  </section>\n\n  <div class=\"course\"></div>\n\n  <section id=\"s5\">\n    <div class=\"shead\"><span class=\"eyebrow\">The Canvas</span></div>\n    <h2>Build on <span class=\"o\">Your HACD</span></h2>\n    <p>You build beside the gold you hold. Every work is modeled on a <strong>HACD you own</strong> \u2014 it is your canvas, and its colors are the target you aim for. The closer a finished work's colors come to that HACD's own palette, the rarer the piece.</p>\n    <ul>\n      <li>One HACD is one canvas \u2014 the reference your craft is measured against.</li>\n      <li>The more HACDs you hold, the more canvases you can work, and the richer the palettes you can chase.</li>\n      <li>Holding a rarer HACD raises the ceiling: mirroring a rare diamond's exact colors is the rarest thing the protocol can hold.</li>\n    </ul>\n    <p>The HACD itself is never spent, altered, or locked \u2014 it remains pure gold. Your work is modeled on it, never carved into it.</p>\n  </section>\n\n  <div class=\"course\"></div>\n\n  <section id=\"s6\">\n    <div class=\"shead\"><span class=\"eyebrow\">Building &amp; Rarity</span></div>\n    <h2>Set the Stones. <span class=\"o\">Earn the Rarity.</span></h2>\n    <p>A work is a design from the native catalog, laid out on a 16\u00d716 grid. <strong>Every filled cell is one stone</strong>, so each design has an exact stone cost. You complete a work by setting real colored stones into every cell. What makes a finished work rare is how its colors relate to the HACD it is built on:</p>\n    <table>\n      <thead><tr><th>Rarity Class</th><th>How It's Made</th></tr></thead>\n      <tbody>\n        <tr><td>Common</td><td>Little overlap with the HACD palette</td></tr>\n        <tr><td>Uncommon</td><td>Partial overlap</td></tr>\n        <tr><td>Rare</td><td>Most colors match</td></tr>\n        <tr><td>Epic</td><td>Near-exact palette</td></tr>\n        <tr><td>Monochrome \u2014 Master</td><td>Built entirely from a single color</td></tr>\n        <tr class=\"tot\"><td>Exact Palette \u2014 Signature</td><td>Replicates the HACD's own colors, stone for stone</td></tr>\n      </tbody>\n    </table>\n    <p>The two master works are the hardest of all. The <strong>Signature</strong> \u2014 an exact palette match \u2014 is the rarest a builder can make. The <strong>Monochrome</strong> \u2014 a work in one pure color \u2014 is the second master class. Both demand stones that Genesis made scarce on purpose, so assembling enough of the right colors, by patient collecting and trading, is the real test of craft.</p>\n  </section>\n\n  <div class=\"course\"></div>\n\n  <section id=\"s7\">\n    <div class=\"shead\"><span class=\"eyebrow\">Native Catalog</span></div>\n    <h2>Nine <span class=\"o\">Native Works</span></h2>\n    <p>The protocol ships with a fixed set of native designs, each built on a 28\u00d728 grid from colored stones \u2014 exactly as they appear in the builder. A design\u2019s stone requirement is fixed by its filled-cell count; the color of a finished work comes entirely from the stones laid into it.</p>\n    <div class=\"pixwrap\" id=\"catalog\"></div>\n  </section>\n\n  <div class=\"course\"></div>\n\n  <section id=\"s7b\">\n    <div class=\"shead\"><span class=\"eyebrow\">Worked Diamonds</span></div>\n    <h2>Finished, <span class=\"o\">in Every Color</span></h2>\n    <p>A finished work is not a separate render \u2014 it is the very thing you build in the dashboard. Because color comes from the stones you lay in, the same design takes on a completely different character depending on its palette: ruby, emerald, sapphire, amber, or clear.</p>\n    <div class=\"pixwrap\" id=\"gallery\"></div>\n  </section>\n\n  <div class=\"course\"></div>\n\n  <section id=\"s8\">\n    <div class=\"shead\"><span class=\"eyebrow\">Completion</span></div>\n    <h2>Finish, and <span class=\"o\">Maybe Strike HAC</span></h2>\n    <p>BRICK never pays out in BRICK. When a work is completed, the protocol <strong>may</strong> reward the builder with a drop of <strong>HAC</strong> \u2014 but the drop is a matter of chance, not a fixed wage. It is not paid on every completion, and when it lands its size varies: one finished work might bring a small drop, another a large one, and many bring nothing at all.</p>\n    <p>Rarer works and rarer HACDs improve both the chance of a drop and how large it can be \u2014 but nothing is owed. The reward recognizes finished craft as a bonus, never as a return on capital.</p>\n    <div class=\"callout\">The HAC drop is funded entirely by real protocol revenue \u2014 the <strong>marketplace commission</strong> \u2014 never by printing BRICK or redistributing deposits. It is chance-based and never guaranteed: a completion may bring a large drop, a small one, or none. BRICK promises no income, yield, or return of any kind.</div>\n  </section>\n\n  <div class=\"course\"></div>\n\n  <section id=\"s9\">\n    <div class=\"shead\"><span class=\"eyebrow\">Completed Works</span></div>\n    <h2>Keep, List, <span class=\"o\">or Dismantle</span></h2>\n    <p>A completed work is a <strong>worked diamond</strong> recorded inside BRICK Protocol \u2014 modeled on your HACD, kept in the protocol's own memory, and viewable at any time. Its stones are held within it for as long as it exists. A builder can do three things with a finished work:</p>\n    <ul>\n      <li><strong>Keep</strong> \u2014 hold the worked diamond in your collection; its stones stay locked inside, and its scarcity is real.</li>\n      <li><strong>List</strong> \u2014 place it on the market, where other participants can acquire the finished piece in HAC.</li>\n      <li><strong>Dismantle</strong> \u2014 break the work apart, returning its colored stones to your hands and to circulation. The diamond is undone; the stones live on to be built again.</li>\n    </ul>\n    <div class=\"callout\">Dismantling is the protocol's pressure valve. Stones locked inside works are genuinely scarce \u2014 but a builder can always demolish to reclaim them, so the building economy never runs permanently dry. A civilization that can build can also rebuild.</div>\n  </section>\n\n  <div class=\"course\"></div>\n\n  <section id=\"s10\">\n    <div class=\"shead\"><span class=\"eyebrow\">The Market</span></div>\n    <h2>Where Scarcity <span class=\"o\">Sets the Price</span></h2>\n    <p>The market runs in <strong>HAC</strong>. Two things change hands there: loose <strong>colored stones</strong>, and finished <strong>worked diamonds</strong>. A participant who missed Genesis becomes a builder here \u2014 by collecting the stones they need, color by color, and showing their craft against their own HACD.</p>\n    <p>This is where scarcity bites. With only a million stones in existence \u2014 and the rare colors among them laid down in tiny numbers \u2014 the price of a color is set entirely by those who want it. There is no faucet and no second printing; every stone in play came from Genesis or from a builder who dismantled a work to release it.</p>\n    <div class=\"callout\">On every sale the protocol takes a flat commission of <span class=\"mono\">2%</span> of the sale price \u2014 a 100 HAC sale returns 2 HAC to the protocol. That commission is the protocol's only revenue, and the source that funds the chance-based completion drops.</div>\n  </section>\n\n  <div class=\"course\"></div>\n\n  <section id=\"s11\">\n    <div class=\"shead\"><span class=\"eyebrow\">Token Flow</span></div>\n    <h2>One <span class=\"o\">Closed Loop</span></h2>\n    <div class=\"flow\">\n      <div class=\"step\"><span class=\"n\">1</span><span class=\"t\"><b>Acquire Colored Stones</b><span>Buy at Genesis, or collect on the market in HAC \u2014 color by color. Supply is fixed at one million.</span></span></div>\n      <div class=\"step\"><span class=\"n\">2</span><span class=\"t\"><b>Choose a Canvas</b><span>Pick a HACD you hold. Its colors are the rarity you aim for; the HACD itself is never touched.</span></span></div>\n      <div class=\"step\"><span class=\"n\">3</span><span class=\"t\"><b>Build</b><span>Set stones into a native design. The closer the colors come to the HACD's palette, the rarer the piece.</span></span></div>\n      <div class=\"step\"><span class=\"n\">4</span><span class=\"t\"><b>Complete \u2192 Worked Diamond</b><span>A crafted diamond is recorded inside BRICK, modeled on your HACD. The HACD itself is untouched.</span></span></div>\n      <div class=\"step\"><span class=\"n\">5</span><span class=\"t\"><b>Chance HAC Drop</b><span>Completion may strike a HAC bonus from the commission pool \u2014 variable in size, and never guaranteed.</span></span></div>\n      <div class=\"step\"><span class=\"n\">6</span><span class=\"t\"><b>Keep, List, or Dismantle</b><span>Hold it, sell it in HAC (2% fee), or break it back into stones to build again.</span></span></div>\n    </div>\n  </section>\n\n  <div class=\"course\"></div>\n\n  <section id=\"s12\">\n    <div class=\"shead\"><span class=\"eyebrow\">Genesis</span></div>\n    <h2>BRICK <span class=\"o\">Genesis Formation</span></h2>\n    <p><strong>What BRICK is:</strong> a fixed-supply colored asset on Hacash whose sole purpose is to be built with. Each stone carries a color; set into a work modeled on your HACD, it becomes craft. BRICK carries no claim, dividend, or promise \u2014 value lives in the works that are built, never in the raw stone.</p>\n    <p>Genesis lays down the <strong>entire</strong> BRICK supply at once. The supply is <strong>fixed at 1,000,000 stones</strong> and is created in full through Genesis Formation (500 slots \u00d7 2,000 stones). There is no team, private, or venture allocation, and <strong>no BRICK is ever minted after Genesis</strong>. Each slot's stones are assigned their 16 colors by chance, following the rarity ladder.</p>\n    <div class=\"callout brick\"><strong>Daily vesting \u2014 the builder's daily draw.</strong> Each slot's 2,000 stones are allocated at Genesis and released by the daily draw: <strong>3 BRICK per day until 2,000</strong> (about 667 days), then it ends. Every day's stones reveal their colors on release, so each lot is a daily draw \u2014 a standing reason to return and see what the rarity ladder gave you. Total supply stays fixed at 1,000,000: vesting releases stones already allocated and never mints new BRICK.</div>\n    <div class=\"callout\"><strong>Launch scope.</strong> Genesis Formation launches the BRICK asset \u2014 one million colored stones, distributed in full. The building interface, works catalog, completion drops, the dismantle function, and the HAC market are planned post-launch features and require separate implementation by the BRICK team.</div>\n    <table>\n      <thead><tr><th>Parameter</th><th>Value</th></tr></thead>\n      <tbody>\n        <tr><td>Genesis Slots</td><td>500</td></tr>\n        <tr><td>Cost Per Slot</td><td><span class=\"o\">1 HACD + 30 HAC</span></td></tr>\n        <tr><td>BRICK Per Slot</td><td>2,000 <span class=\"o\">(3/day)</span></td></tr>\n        <tr><td>Stone Colors</td><td>Random \u2014 revealed daily as bricks open</td></tr>\n        <tr><td>Participation</td><td>Open</td></tr>\n        <tr><td>Daily Draw</td><td>3 BRICK / day to 2,000 (~667 days)</td></tr>\n        <tr><td>Team / Private / VC Allocation</td><td>None</td></tr>\n        <tr><td>Further Minting</td><td>None</td></tr>\n        <tr class=\"tot\"><td>Total Supply (Fixed)</td><td>1,000,000 BRICK</td></tr>\n      </tbody>\n    </table>\n    <ul><li>Open participation</li><li>No private allocation</li><li>No venture capital allocation</li><li>No team allocation</li></ul>\n  </section>\n\n  <div class=\"course\"></div>\n\n  <section>\n    <div class=\"shead\"><span class=\"eyebrow\">Closing</span></div>\n    <h2>Be the Builder, <span class=\"o\">Not the Consumer</span></h2>\n    <p class=\"lead\">BRICK brings scarcity, production, and creativity together in a single system. Its purpose is simple: to let people become not just consumers but builders of the digital world \u2014 crafting works of their own beside the gold they hold, without ever having to part with it.</p>\n  </section>\n\n  <div class=\"foot\">\n    <span class=\"em\">DISCLAIMER</span> \u2014 This document describes the purpose and function of BRICK Protocol for informational purposes only. It is not investment advice, an offer, or a solicitation. BRICK is a fixed-supply utility asset for producing works; it is not a security, carries no claim or dividend, and the protocol makes no promise of profit, income, or return. Completion rewards are chance-based, variable, and never guaranteed \u2014 a completed work may bring no reward at all. Participation in Genesis or any ecosystem activity does not constitute an investment or a guarantee of any kind. Features remain subject to development and implementation.<br><br>\n    BRICK Protocol \u00b7 Whitepaper \u00b7 Proof of Building Economy<br>\n    HACD Native \u00b7 Launch on HACD Labs \u00b7 0% Team Allocation<br>\n    Genesis Formation \u00b7 500 Slots \u00b7 1 HACD + 30 HAC per Slot\n  </div>\n</div>\n\n<script>\n// gold pixel renderer\nfunction pixGrid(p,cell){\n  const n=p.length;\n  const g=document.createElement('div');g.className='pgrid';\n  g.style.gridTemplateColumns=`repeat(${n},${cell}px)`;\n  g.style.gridTemplateRows=`repeat(${n},${cell}px)`;\n  p.forEach(row=>[...row].forEach(c=>{\n    const d=document.createElement('div');d.className='pc '+(c!=='0'?'on':'off');g.appendChild(d);\n  }));\n  return g;\n}\n// cover emblem: Crown (regal, worked gold)\nconst crown=['0000000000000000','0000000000000000','0010000000000100','0110000110000110','0110001111000110','0111001111001110','0111111111111110','0111111111111110','0111111111111110','0111111111111110','0011111111111100','0011111111111100','0000000000000000','0000000000000000','0000000000000000','0000000000000000'];\n// cover emblem: build \u2192 3D faceted diamond\nconst GEM=[\n\"0000111111110000\",\"0001111111111000\",\"0011111111111100\",\"0111111111111110\",\n\"1111111111111111\",\"0111111111111110\",\"0011111111111100\",\"0011111111111100\",\n\"0001111111111000\",\"0001111111111000\",\"0000111111110000\",\"0000011111100000\",\n\"0000011111100000\",\"0000001111000000\",\"0000000110000000\",\"0000000110000000\"];\n(function(){\n  const g=document.getElementById('gem');\n  g.style.gridTemplateColumns='repeat(16,13px)';\n  g.style.gridTemplateRows='repeat(16,13px)';\n  const reduce=window.matchMedia('(prefers-reduced-motion: reduce)').matches;\n  GEM.forEach((row,r)=>{[...row].forEach(ch=>{\n    const d=document.createElement('div');\n    d.className='pc '+(ch!=='0'?'on':'off');\n    if(ch!=='0'&&!reduce){d.style.animationDelay=(r*52+Math.random()*40)+'ms';}\n    g.appendChild(d);\n  });});\n  if(!reduce){const m=document.getElementById('gemmorph');setTimeout(()=>m.classList.add('done'),1500);}\n})();\n\n// color table\nconst COLORS=[['Red','#E8572A','S','2.0'],['Blue','#3A7CA5','S','2.5'],['Pink','#E07AB0','S','3.0'],\n['Purple','#9B7BD4','A','3.5'],['Green','#5BBF8A','A','4.0'],['Orange','#F08A29','A','4.5'],\n['Indigo','#6C6CE0','B','5.0'],['Turquoise','#4EC9C9','B','5.5'],['Gold','#F0B429','C','6.5'],\n['Amber','#E8B84E','C','7.0'],['Rose','#E05A5A','C','7.5'],['Teal','#2FA8A0','C','8.0'],\n['Sky','#6DB3E8','D','9.0'],['Mint','#7FD4A8','D','9.5'],['Lime','#A8D04E','D','10.0'],['Slate','#8A99AD','D','12.5']];\ndocument.getElementById('colortable').innerHTML=COLORS.map(([n,c,t,d])=>\n  `<tr><td><span class=\"sw\" style=\"background:${c}\"></span>${n}</td><td style=\"color:var(--faint)\">${t}</td><td>${d}%</td></tr>`).join('');\n\n// catalog: all 21 native works (16x16, properly formed)\nconst works={\n Solitaire:['0000000110000000','0000001111000000','0000011111100000','0000111111110000','0001111111111000','0011111111111100','0111111111111110','1111111111111111','1111111111111111','0111111111111110','0011111111111100','0001111111111000','0000111111110000','0000011111100000','0000001111000000','0000000110000000'],\n Brilliant:['0000011111100000','0001111111111000','0011111111111100','0111111111111110','0111111111111110','1111111111111111','1111111111111111','1111111111111111','1111111111111111','1111111111111111','1111111111111111','0111111111111110','0111111111111110','0011111111111100','0001111111111000','0000011111100000'],\n Princess:['1111111111111111','1111111111111111','1111111111111111','1111111111111111','1111111111111111','1111111111111111','1111111111111111','1111111111111111','1111111111111111','1111111111111111','1111111111111111','1111111111111111','1111111111111111','1111111111111111','1111111111111111','1111111111111111'],\n Emerald:['0000000000000000','0000000000000000','0000000000000000','0000000000000000','0001111111111000','0111111111111110','0111111111111110','0111111111111110','0111111111111110','0111111111111110','0111111111111110','0001111111111000','0000000000000000','0000000000000000','0000000000000000','0000000000000000'],\n Radiant:['0000000000000000','0000111111110000','0001111111111000','0011111111111100','0111111111111110','0111111111111110','0111111111111110','0111111111111110','0111111111111110','0111111111111110','0111111111111110','0111111111111110','0011111111111100','0001111111111000','0000111111110000','0000000000000000'],\n Pear:['0000000000000000','0000000110000000','0000001111000000','0000011111100000','0000111111110000','0001111111111000','0011111111111100','0011111111111100','0011111111111100','0011111111111100','0011111111111100','0011111111111100','0011111111111100','0001111111111000','0000111111110000','0000011111100000'],\n Oval:['0000000000000000','0000001111000000','0001111111111000','0011111111111100','0111111111111110','0111111111111110','1111111111111111','1111111111111111','1111111111111111','1111111111111111','0111111111111110','0111111111111110','0011111111111100','0001111111111000','0000001111000000','0000000000000000'],\n Heart:['0000000000000000','0111111001111110','1111111111111111','1111111111111111','1111111111111111','1111111111111111','1111111111111111','1111111111111111','1111111111111111','1111111111111111','0111111111111110','0111111111111110','0011111111111100','0001111111111000','0000111111110000','0000011111100000'],\n Marquise:['0000000000000000','0000000000000000','0000000000000000','0000000000000000','0000111111110000','0011111111111100','0111111111111110','1111111111111111','1111111111111111','0111111111111110','0011111111111100','0000111111110000','0000000000000000','0000000000000000','0000000000000000','0000000000000000'],\n Necklace:['0001100000011000','0010010000100100','0010001001000100','0000000110000000','0000000110000000','0000001111000000','0000011111100000','0000111111110000','0000111111110000','0000011111100000','0000001111000000','0000000110000000','0000000000000000','0000000000000000','0000000000000000','0000000000000000'],\n Bracelet:['0000011111100000','0001111111111000','0011110000111100','0111000000001110','0110000000000110','1110000000000111','1100000000000011','1100000000000011','1100000000000011','1100000000000011','1110000000000111','0110000000000110','0111000000001110','0011110000111100','0001111111111000','0000011111100000'],\n Ring:['0000011111100000','0001111111111000','0011111111111100','0111110000111110','0111000000001110','1111000000001111','1110000000000111','1110000000000111','1110000000000111','1110000000000111','1111000000001111','0111000000001110','0111110000111110','0011111111111100','0001111111111000','0000011111100000'],\n Crown:crown,\n Earrings:['0001000000001000','0001000000001000','0001000000001000','0011100000011100','0111110000111110','0111110000111110','0111110000111110','0011100000011100','0001000000001000','0000000000000000','0000000000000000','0000000000000000','0000000000000000','0000000000000000','0000000000000000','0000000000000000'],\n Ingot:['0000000000000000','0000000000000000','0000000000000000','0000000000000000','0000000000000000','0000011111100000','0000111111110000','0000111111110000','0001111111111000','0011111111111100','0011111111111100','0111111111111110','0000000000000000','0000000000000000','0000000000000000','0000000000000000'],\n Goblet:['0000000000000000','0111111111111000','0111111111111000','0111111111100000','0011111111000000','0001111110000000','0000111100000000','0000011000000000','0000011000000000','0000011000000000','0000011000000000','0000111100000000','0001111110000000','0011111111000000','0111111111111000','0000000000000000'],\n Key:['0000111100000000','0001000010000000','0010000001000000','0010000001000000','0010000001000000','0001000010000000','0000111100000000','0000011000000000','0000011000000000','0000011000000000','0000011000000000','0000011100000000','0000011010000000','0000011100000000','0000011010000000','0000011110000000'],\n Watch:['0000001111000000','0000001001000000','0000011111100000','0000111111110000','0001111111111000','0011111111111100','0011110011111100','0011110011111100','0011111100111100','0011111111111100','0001111111111000','0000111111110000','0000011111100000','0000000000000000','0000000000000000','0000000000000000'],\n Car:['0000000000000000','0000000000000000','0000000000000000','0000011111100000','0000111111110000','0001111111111000','0111111111111111','0111111111111111','0111111111111111','0111111111111111','0111111111111111','0011011111101100','0111101111011110','0111101111011110','0011000110001100','0000000000000000'],\n House:['0000000000000000','0000000110000000','0000001111000000','0000011111100000','0000111111110000','0001111111111000','0011111111111100','0111111111111110','0111111111111110','0111001111001110','0111001111001110','0111001111001110','0111000000001110','0111000000001110','0111111111111110','0000000000000000'],\n};\n// isometric 3D voxel renderer \u2014 gradient-lit gold cubes + contact shadow\nfunction vface(x,pts,fill,edge){\n  x.beginPath();x.moveTo(pts[0][0],pts[0][1]);\n  for(let i=1;i<pts.length;i++)x.lineTo(pts[i][0],pts[i][1]);\n  x.closePath();x.fillStyle=fill;x.fill();\n  if(edge){x.lineWidth=.5;x.strokeStyle=edge;x.stroke();}\n}\nfunction vgrad(x,x0,y0,x1,y1,c0,c1){const g=x.createLinearGradient(x0,y0,x1,y1);g.addColorStop(0,c0);g.addColorStop(1,c1);return g;}\nfunction voxIso(p){\n  const TW=7,TH=3.5,D=6,pad=9,sdx=3,sdy=5,DPR=Math.min(2,window.devicePixelRatio||1);\n  const cells=[];\n  p.forEach((row,r)=>[...row].forEach((ch,c)=>{ if(ch!=='0') cells.push([c,r]); }));\n  const cv=document.createElement('canvas');\n  if(!cells.length){cv.width=cv.height=1;return cv;}\n  let minX=1e9,maxX=-1e9,minY=1e9,maxY=-1e9;\n  cells.forEach(([c,r])=>{const px=(c-r)*TW/2,py=(c+r)*TH/2;\n    minX=Math.min(minX,px-TW/2);maxX=Math.max(maxX,px+TW/2);\n    minY=Math.min(minY,py-TH/2);maxY=Math.max(maxY,py+TH/2+D);});\n  const W=Math.ceil(maxX-minX)+pad*2,H=Math.ceil(maxY-minY)+pad*2,offX=-minX+pad,offY=-minY+pad;\n  cv.width=W*DPR;cv.height=H*DPR;cv.style.width=W+'px';cv.style.height=H+'px';\n  const x=cv.getContext('2d');x.scale(DPR,DPR);x.lineJoin='round';\n  cells.sort((a,b)=>(a[0]+a[1])-(b[0]+b[1])||a[0]-b[0]);\n  // soft contact shadow (solid union on offscreen, blurred when blitted -> no patchiness)\n  const sh=document.createElement('canvas');sh.width=cv.width;sh.height=cv.height;\n  const sx=sh.getContext('2d');sx.scale(DPR,DPR);sx.fillStyle='#000';\n  cells.forEach(([c,r])=>{const px=(c-r)*TW/2+offX+sdx,py=(c+r)*TH/2+offY+D+sdy;\n    sx.beginPath();sx.moveTo(px,py-TH/2);sx.lineTo(px+TW/2,py);sx.lineTo(px,py+TH/2);sx.lineTo(px-TW/2,py);sx.closePath();sx.fill();});\n  x.save();x.filter='blur(2.5px)';x.globalAlpha=.3;x.drawImage(sh,0,0,W,H);x.restore();\n  // cubes, back to front\n  const EDGE='rgba(40,24,4,.3)';\n  cells.forEach(([c,r])=>{const px=(c-r)*TW/2+offX,py=(c+r)*TH/2+offY;\n    vface(x,[[px-TW/2,py],[px,py+TH/2],[px,py+TH/2+D],[px-TW/2,py+D]],vgrad(x,px,py,px,py+TH/2+D,'#C9912F','#7A5016'),EDGE);\n    vface(x,[[px,py+TH/2],[px+TW/2,py],[px+TW/2,py+D],[px,py+TH/2+D]],vgrad(x,px,py,px,py+D,'#90631B','#523809'),EDGE);\n    vface(x,[[px,py-TH/2],[px+TW/2,py],[px,py+TH/2],[px-TW/2,py]],vgrad(x,px,py-TH/2,px,py+TH/2,'#FCEFC8','#E6B85E'),EDGE);});\n  return cv;\n}\n/* dashboard-style asset renderer: path -> 28x28 raster -> colored brick mosaic */\nconst BRICK16=[['Ruby','#e11d2e'],['Emerald','#1bb56b'],['Sapphire','#2668ff'],['Violet','#7a2cf0'],['Rose','#ea5ba7'],['Amber','#f58a17'],['Cyan','#21c6d8'],['Citrine','#f1cf28'],['Teal','#2fb6a8'],['Magenta','#d34ee2'],['Lime','#9ad318'],['Indigo','#4753e8'],['Slate','#8b98a8'],['Bronze','#a66a2d'],['Ash','#c1c7d0'],['Clear','#ece9de']];\nconst GRID=28;\nconst DSHAPES=[\n {id:'heart',label:'Heart',path:'M50 85 L16 51 L16 30 L28 16 L40 16 L50 27 L60 16 L72 16 L84 30 L84 51 Z'},\n {id:'emerald',label:'Emerald',path:'M26 12 L74 12 L88 26 L88 74 L74 88 L26 88 L12 74 L12 26 Z'},\n {id:'circle',label:'Halo',path:'M50 10 A40 40 0 1 1 49.999 10 Z'},\n {id:'pear',label:'Pear',path:'M50 12 C68 21 82 39 82 58 C82 78 68 90 50 90 C32 90 18 78 18 58 C18 39 32 21 50 12 Z'},\n {id:'diamond',label:'Brilliant',path:'M50 12 L82 28 L92 44 L50 90 L8 44 L18 28 Z'},\n {id:'oval',label:'Oval',path:'M50 8 C67 8 80 25 80 50 C80 75 67 92 50 92 C33 92 20 75 20 50 C20 25 33 8 50 8 Z'},\n {id:'triangle',label:'Trillion',path:'M50 10 L92 88 L8 88 Z'},\n {id:'thin-diamond',label:'Marquise',path:'M50 8 L74 28 L86 50 L74 72 L50 92 L26 72 L14 50 L26 28 Z'},\n {id:'hexagon',label:'Hexagon',path:'M50 7 L80 25 L80 75 L50 93 L20 75 L20 25 Z'}\n];\nfunction shapeRows(pathData,n){\n  const cv=document.createElement('canvas');cv.width=100;cv.height=100;const ctx=cv.getContext('2d');\n  if(!ctx||typeof Path2D==='undefined')return Array.from({length:n},()=>'1'.repeat(n));\n  const path=new Path2D(pathData);\n  return Array.from({length:n},(_,r)=>{let row='';for(let c=0;c<n;c++){const x=((c+0.5)/n)*100,y=((r+0.5)/n)*100;row+=ctx.isPointInPath(path,x,y)?'1':'0';}return row;});\n}\nDSHAPES.forEach(s=>{s.rows=shapeRows(s.path,GRID);s.cells=s.rows.join('').split('').filter(c=>c==='1').length;});\nfunction previewHTML(shape,pick){\n  let cells='';\n  shape.rows.forEach((row,r)=>{row.split('').forEach((cell,c)=>{ cells+= cell!=='1' ? '<div class=\"apc\"></div>' : '<div class=\"apc f\" style=\"--bc:'+pick(r,c)+'\"></div>'; });});\n  return '<div class=\"apshell\"><div class=\"apgrid\" style=\"grid-template-columns:repeat('+GRID+',minmax(0,1fr))\">'+cells+'</div></div>';\n}\nconst palette=BRICK16.map(c=>c[1]);\nconst mix=()=>palette[Math.floor(Math.random()*palette.length)];\nconst cw=document.getElementById('catalog');\nDSHAPES.forEach(s=>{\n  const wrap=document.createElement('div');wrap.className='pix';\n  wrap.innerHTML=previewHTML(s,mix);\n  const l=document.createElement('div');l.className='lbl';l.innerHTML='<b>'+s.label+'</b>'+s.cells+' bricks';\n  wrap.appendChild(l);cw.appendChild(wrap);\n});\nconst byId=Object.fromEntries(DSHAPES.map(s=>[s.id,s]));\nconst GAL=[['heart','Ruby','#e11d2e'],['heart','Emerald','#1bb56b'],['heart','Sapphire','#2668ff'],['diamond','Clear','#ece9de'],['diamond','Violet','#7a2cf0'],['hexagon','Amber','#f58a17'],['oval','Rose','#ea5ba7'],['emerald','Citrine','#f1cf28'],['triangle','Lime','#9ad318'],['thin-diamond','Cyan','#21c6d8'],['pear','Teal','#2fb6a8'],['circle','Magenta','#d34ee2']];\nconst gal=document.getElementById('gallery');\nGAL.forEach(([id,cname,hex])=>{\n  const s=byId[id];if(!s)return;\n  const wrap=document.createElement('div');wrap.className='pix';\n  wrap.innerHTML=previewHTML(s,()=>hex);\n  const l=document.createElement('div');l.className='lbl';l.innerHTML='<b>'+s.label+'</b>'+cname;\n  wrap.appendChild(l);gal.appendChild(wrap);\n});\n</script>\n</body>\n</html>\n",
  "genesis": "<!doctype html>\n<html lang=\"en\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n<title>BRICK Protocol \u2014 Genesis Formation</title>\n<style>\n  :root{\n    --obsidian:#0A0D12; --panel:#0E131A; --panel2:#0c1118; --raise:#121922;\n    --parch:#ECE5D6; --parch-dim:#b8b2a4; --ash:#7e8794; --faint:#4a525d;\n    --gold:#E3A93E; --gold-hi:#F6DC9A; --gold-lo:#B9822B;\n    --brick:#E8572A;\n    --line:rgba(227,169,62,.16); --line-soft:rgba(236,229,214,.07);\n    --mono:'Courier New',ui-monospace,Menlo,Consolas,monospace;\n    --sans:system-ui,-apple-system,'Segoe UI',Helvetica,Arial,sans-serif;\n    --black:'Arial Black','Helvetica Neue',Helvetica,Arial,sans-serif;\n    --serif:Georgia,'Times New Roman',serif;\n  }\n  *,*::before,*::after{margin:0;padding:0;box-sizing:border-box}\n  html{scroll-behavior:smooth}\n  body{\n    background:\n      radial-gradient(1100px 700px at 50% -260px, rgba(227,169,62,.10), transparent 60%),\n      radial-gradient(900px 520px at 100% 120%, rgba(232,87,42,.06), transparent 55%),\n      var(--obsidian);\n    color:var(--parch);font-family:var(--sans);font-size:16px;line-height:1.7;-webkit-font-smoothing:antialiased;\n    overflow-x:hidden;\n  }\n  .wrap{max-width:1080px;margin:0 auto;padding:0 28px}\n  a{color:inherit;text-decoration:none}\n  .mono{font-family:var(--mono)}\n  .o{color:var(--gold)}\n\n  /* brick course divider */\n  .course{height:7px;margin:0;\n    background:\n      repeating-linear-gradient(90deg, var(--gold-lo) 0 16px, transparent 16px 19px),\n      repeating-linear-gradient(90deg, transparent 0 8px, var(--gold) 8px 24px, transparent 24px 27px);\n    opacity:.20}\n\n  /* ===== NAV ===== */\n  nav.top{position:sticky;top:0;z-index:50;backdrop-filter:blur(10px);\n    background:linear-gradient(180deg,rgba(10,13,18,.92),rgba(10,13,18,.72));\n    border-bottom:1px solid var(--line)}\n  nav.top .wrap{display:flex;align-items:center;justify-content:space-between;height:62px}\n  .brand{font-family:var(--black);font-weight:900;letter-spacing:-1px;font-size:21px}\n  .brand .foil{background:linear-gradient(94deg,var(--gold-lo),var(--gold-hi) 45%,var(--gold-lo));-webkit-background-clip:text;background-clip:text;-webkit-text-fill-color:transparent}\n  .brand span.l{color:var(--ash);font-family:var(--mono);font-weight:400;font-size:11px;letter-spacing:.28em;margin-left:10px;text-transform:uppercase}\n  .navlinks{display:flex;gap:26px;align-items:center;font-family:var(--mono);font-size:12px;letter-spacing:.12em;text-transform:uppercase;color:var(--parch-dim)}\n  .navlinks a:hover{color:var(--gold)}\n  .navlinks .live{display:inline-flex;align-items:center;gap:8px;color:var(--gold);border:1px solid var(--line);border-radius:2px;padding:7px 12px}\n  .navlinks .live::before{content:\"\";width:7px;height:7px;border-radius:50%;background:var(--gold);box-shadow:0 0 0 0 rgba(227,169,62,.6);animation:pulse 2s infinite}\n  @keyframes pulse{0%{box-shadow:0 0 0 0 rgba(227,169,62,.5)}70%{box-shadow:0 0 0 7px rgba(227,169,62,0)}100%{box-shadow:0 0 0 0 rgba(227,169,62,0)}}\n  @media(max-width:760px){.navlinks a:not(.live){display:none}}\n\n  /* ===== HERO ===== */\n  .hero{padding:74px 0 64px}\n  .hero .wrap{display:grid;grid-template-columns:1.05fr .95fr;gap:56px;align-items:center}\n  .kicker{font-family:var(--mono);font-size:11px;letter-spacing:.4em;text-transform:uppercase;color:var(--ash)}\n  .hero h1{font-family:var(--black);font-weight:900;font-size:clamp(40px,6.6vw,72px);line-height:.96;letter-spacing:-2.5px;margin:18px 0 0}\n  .hero h1 .g{color:var(--gold)}\n  .hero .sub{font-family:var(--serif);font-style:italic;color:var(--parch-dim);font-size:clamp(17px,2.4vw,21px);line-height:1.45;max-width:520px;margin:22px 0 0}\n  .cta-row{display:flex;gap:14px;flex-wrap:wrap;margin-top:34px}\n  .btn{font-family:var(--mono);font-size:13px;letter-spacing:.1em;text-transform:uppercase;padding:15px 26px;border-radius:2px;border:1px solid var(--line);transition:.18s;display:inline-flex;align-items:center;gap:9px}\n  .btn.primary{background:linear-gradient(145deg,var(--gold-hi),var(--gold-lo));color:#1a1206;border-color:transparent;font-weight:700;box-shadow:0 8px 30px -10px rgba(227,169,62,.5)}\n  .btn.primary:hover{transform:translateY(-2px);box-shadow:0 14px 38px -10px rgba(227,169,62,.6)}\n  .btn.ghost{color:var(--parch)}\n  .btn.ghost:hover{border-color:var(--gold);color:var(--gold)}\n  .statstrip{display:flex;gap:30px;margin-top:40px;flex-wrap:wrap}\n  .statstrip .s .v{font-family:var(--black);font-size:24px;color:var(--gold);letter-spacing:-.5px}\n  .statstrip .s .k{font-family:var(--mono);font-size:10px;letter-spacing:.18em;text-transform:uppercase;color:var(--ash);margin-top:2px}\n\n  /* hero gem */\n  .gemstage{display:flex;flex-direction:column;align-items:center;gap:20px}\n  .pedestal{position:relative;padding:30px;border:1px solid var(--line);border-radius:4px;\n    background:radial-gradient(420px 320px at 50% 20%,rgba(227,169,62,.10),transparent 70%),var(--panel)}\n  .pedestal::after{content:\"\";position:absolute;inset:0;border-radius:4px;pointer-events:none;\n    background:linear-gradient(115deg,transparent 30%,rgba(246,220,154,.10) 47%,transparent 60%);\n    background-size:280% 100%;animation:sheen 6s ease-in-out infinite}\n  @keyframes sheen{0%,100%{background-position:140% 0}50%{background-position:-40% 0}}\n  .pgrid{display:grid;gap:2px}\n  .pc{width:13px;height:13px;border-radius:1px;background:transparent}\n  .pc.on{background:linear-gradient(145deg,var(--gold-hi),var(--gold-lo));box-shadow:inset 0 -1px 0 rgba(0,0,0,.4),inset 0 1px 0 rgba(255,255,255,.22)}\n  .gemcap{font-family:var(--mono);font-size:11px;letter-spacing:.16em;text-transform:uppercase;color:var(--ash);text-align:center}\n  .stonestrip{display:flex;gap:5px;flex-wrap:wrap;justify-content:center;max-width:300px}\n  .stone{width:17px;height:17px;border-radius:2px;box-shadow:inset 0 -2px 0 rgba(0,0,0,.35),inset 0 1px 0 rgba(255,255,255,.25)}\n  @media(max-width:880px){.hero .wrap{grid-template-columns:1fr;gap:44px}.gemstage{order:-1}}\n\n  /* ===== SECTION SHELL ===== */\n  section.blk{padding:72px 0}\n  .eyebrow{font-family:var(--mono);font-size:11px;letter-spacing:.36em;text-transform:uppercase;color:var(--gold);font-weight:700}\n  h2{font-family:var(--black);font-weight:900;font-size:clamp(28px,4.6vw,42px);letter-spacing:-1.3px;line-height:1.02;margin:12px 0 0;color:var(--parch)}\n  h2 .o{color:var(--gold)}\n  .lead{color:var(--parch-dim);max-width:640px;margin-top:16px;font-size:17px}\n\n  /* ===== GENESIS CARD ===== */\n  .genesis{background:linear-gradient(180deg,var(--panel),var(--panel2));border:1px solid var(--line);border-radius:6px;overflow:hidden;margin-top:30px}\n  .genesis .top{display:grid;grid-template-columns:1.2fr 1fr;gap:0}\n  .gx{padding:38px}\n  .gx.l{border-right:1px solid var(--line)}\n  .gx .lab{font-family:var(--mono);font-size:10px;letter-spacing:.2em;text-transform:uppercase;color:var(--ash)}\n  .price{font-family:var(--black);font-size:clamp(30px,4vw,40px);color:var(--gold);letter-spacing:-1px;margin:6px 0 2px}\n  .price small{font-family:var(--mono);font-size:13px;color:var(--parch-dim);letter-spacing:0;font-weight:400}\n  .getline{font-family:var(--mono);font-size:13px;color:var(--parch);margin-top:14px}\n  .getline b{color:var(--gold)}\n  .glist{list-style:none;margin-top:20px;display:grid;gap:10px}\n  .glist li{font-family:var(--mono);font-size:12.5px;color:var(--parch-dim);display:flex;gap:10px;align-items:flex-start}\n  .glist li::before{content:\"\u25c6\";color:var(--gold);font-size:10px;margin-top:3px}\n  .progwrap{margin-top:6px}\n  .progmeta{display:flex;justify-content:space-between;font-family:var(--mono);font-size:11px;color:var(--ash);letter-spacing:.1em;text-transform:uppercase;margin-bottom:10px}\n  .progmeta .c{color:var(--gold)}\n  .track{height:10px;border-radius:6px;background:var(--raise);border:1px solid var(--line);overflow:hidden}\n  .fill{height:100%;width:0;border-radius:6px;background:linear-gradient(90deg,var(--gold-lo),var(--gold-hi));transition:width 1.4s cubic-bezier(.2,.8,.2,1)}\n  .gx.r .btn.primary{width:100%;justify-content:center;margin-top:26px}\n  .gnote{font-family:var(--mono);font-size:10.5px;color:var(--ash);text-align:center;margin-top:14px;line-height:1.7}\n  .gbar{display:flex;flex-wrap:wrap;gap:8px 26px;padding:18px 38px;border-top:1px solid var(--line);font-family:var(--mono);font-size:11px;color:var(--ash);letter-spacing:.1em;text-transform:uppercase}\n  .gbar b{color:var(--gold);font-weight:400}\n  @media(max-width:760px){.genesis .top{grid-template-columns:1fr}.gx.l{border-right:none;border-bottom:1px solid var(--line)}}\n\n  /* ===== STEPS ===== */\n  .steps{display:grid;grid-template-columns:repeat(4,1fr);gap:18px;margin-top:34px}\n  .step{background:var(--panel);border:1px solid var(--line);border-radius:5px;padding:24px;position:relative;transition:.2s}\n  .step:hover{border-color:rgba(227,169,62,.4);transform:translateY(-3px)}\n  .step .n{font-family:var(--black);font-size:13px;color:#1a1206;background:linear-gradient(145deg,var(--gold-hi),var(--gold-lo));width:30px;height:30px;border-radius:3px;display:flex;align-items:center;justify-content:center}\n  .step h4{font-family:var(--sans);font-weight:800;font-size:16px;margin:16px 0 8px;color:var(--parch)}\n  .step p{font-size:13.5px;color:var(--parch-dim);line-height:1.55}\n  @media(max-width:880px){.steps{grid-template-columns:repeat(2,1fr)}}\n  @media(max-width:480px){.steps{grid-template-columns:1fr}}\n\n  /* ===== STONES LADDER ===== */\n  .ladder{margin-top:30px;border:1px solid var(--line);border-radius:5px;overflow:hidden}\n  .lrow{display:grid;grid-template-columns:30px 1fr 92px 64px;align-items:center;gap:16px;padding:11px 18px;border-bottom:1px solid var(--line-soft);font-family:var(--mono);font-size:12.5px}\n  .lrow:last-child{border-bottom:none}\n  .lrow:hover{background:rgba(227,169,62,.04)}\n  .lrow .sw{width:18px;height:18px;border-radius:3px;box-shadow:inset 0 -2px 0 rgba(0,0,0,.35),inset 0 1px 0 rgba(255,255,255,.25)}\n  .lrow .nm{color:var(--parch)}\n  .lrow .ti{color:var(--ash);text-align:right;font-size:11px;letter-spacing:.06em}\n  .lrow .sh{color:var(--gold);text-align:right}\n  .ladhead{background:rgba(227,169,62,.05);color:var(--gold);text-transform:uppercase;font-size:10px;letter-spacing:.13em}\n  .ladhead .nm,.ladhead .ti,.ladhead .sh{color:var(--gold)}\n\n  /* ===== MASTER CLASSES ===== */\n  .masters{display:grid;grid-template-columns:1fr 1fr;gap:18px;margin-top:32px}\n  .mcard{border:1px solid var(--line);border-radius:6px;padding:30px;background:linear-gradient(180deg,var(--panel),var(--panel2));position:relative;overflow:hidden}\n  .mcard .rank{position:absolute;top:18px;right:20px;font-family:var(--mono);font-size:10px;letter-spacing:.2em;color:var(--ash);text-transform:uppercase}\n  .mcard h3{font-family:var(--black);font-size:23px;letter-spacing:-.6px;color:var(--gold);margin-bottom:10px}\n  .mcard p{font-size:14px;color:var(--parch-dim);line-height:1.55}\n  .mchip{display:inline-block;margin-top:16px;font-family:var(--mono);font-size:10px;letter-spacing:.14em;text-transform:uppercase;color:var(--brick);border:1px solid rgba(232,87,42,.3);border-radius:2px;padding:5px 10px}\n  @media(max-width:680px){.masters{grid-template-columns:1fr}}\n\n  /* ===== PILLARS ===== */\n  .pillars{display:grid;grid-template-columns:repeat(4,1fr);gap:0;margin-top:32px;border:1px solid var(--line);border-radius:5px;overflow:hidden}\n  .pillar{padding:28px;border-right:1px solid var(--line)}\n  .pillar:last-child{border-right:none}\n  .pillar .ic{font-family:var(--black);color:var(--gold);font-size:22px}\n  .pillar h4{font-size:15px;font-weight:800;margin:14px 0 7px}\n  .pillar p{font-size:13px;color:var(--parch-dim);line-height:1.5}\n  @media(max-width:880px){.pillars{grid-template-columns:1fr 1fr}.pillar:nth-child(2){border-right:none}.pillar:nth-child(1),.pillar:nth-child(2){border-bottom:1px solid var(--line)}}\n  @media(max-width:480px){.pillars{grid-template-columns:1fr}.pillar{border-right:none;border-bottom:1px solid var(--line)}.pillar:last-child{border-bottom:none}}\n\n  /* ===== FAQ ===== */\n  .faq{margin-top:30px;max-width:780px}\n  details{border-bottom:1px solid var(--line);padding:6px 0}\n  summary{cursor:pointer;list-style:none;padding:16px 0;font-weight:700;font-size:16px;display:flex;justify-content:space-between;gap:16px;color:var(--parch)}\n  summary::-webkit-details-marker{display:none}\n  summary::after{content:\"+\";color:var(--gold);font-family:var(--mono);font-size:20px;transition:.2s}\n  details[open] summary::after{transform:rotate(45deg)}\n  details p{padding:0 0 18px;color:var(--parch-dim);font-size:14.5px;max-width:680px}\n\n  /* ===== FOOTER ===== */\n  footer{border-top:1px solid var(--line);padding:46px 0 60px;margin-top:20px}\n  .foot-grid{display:flex;justify-content:space-between;gap:30px;flex-wrap:wrap;align-items:flex-start}\n  .foot-links{display:flex;gap:24px;font-family:var(--mono);font-size:12px;letter-spacing:.1em;text-transform:uppercase;color:var(--parch-dim)}\n  .foot-links a:hover{color:var(--gold)}\n  .addr{font-family:var(--mono);font-size:11px;color:var(--ash);margin-top:18px}\n  .addr b{color:var(--gold)}\n  .addr code{color:var(--parch-dim);border:1px solid var(--line);border-radius:2px;padding:3px 8px;display:inline-block;margin-top:6px}\n  .disc{font-family:var(--mono);font-size:10.5px;color:var(--faint);line-height:1.8;margin-top:26px;max-width:880px}\n  .disc .em{color:var(--gold)}\n\n  /* reveal */\n  .rv{opacity:0;transform:translateY(18px);transition:opacity .7s ease,transform .7s ease}\n  .rv.in{opacity:1;transform:none}\n  @media(prefers-reduced-motion:reduce){.rv{opacity:1;transform:none;transition:none}.pedestal::after,.navlinks .live::before{animation:none}}\n\n  /* ===== build \u2192 3D faceted gem ===== */\n  .gemmorph{position:relative;display:grid;place-items:center;width:240px;height:240px;perspective:780px}\n  .pixgem,.facetgem{grid-area:1/1}\n  .pixgem{transition:opacity .7s ease,transform .7s ease}\n  .pixgem .pc.on{opacity:0;animation:drop .46s ease forwards}\n  @keyframes drop{0%{opacity:0;transform:translateY(-11px) scale(.25)}100%{opacity:1;transform:none}}\n  .facetgem{width:188px;height:206px;opacity:0;transform:rotateY(-14deg) scale(.6);transform-style:preserve-3d;\n    filter:drop-shadow(0 20px 24px rgba(0,0,0,.5)) drop-shadow(0 0 18px rgba(227,169,62,.28))}\n  .facetgem .edge polygon{stroke:rgba(40,26,6,.5);stroke-width:.6;stroke-linejoin:round}\n  .gemmorph.done .pixgem{opacity:0;transform:scale(1.16) translateY(-7px)}\n  .gemmorph.done .facetgem{opacity:1;animation:gemin .9s cubic-bezier(.2,.9,.2,1) forwards, idle 7.5s ease-in-out 1s infinite}\n  @keyframes gemin{0%{opacity:0;transform:rotateY(-32deg) scale(.55)}100%{opacity:1;transform:rotateY(-14deg) scale(1)}}\n  @keyframes idle{0%,100%{transform:rotateY(-14deg) rotateX(6deg) translateY(0)}50%{transform:rotateY(14deg) rotateX(-3deg) translateY(-7px)}}\n  .sparkle{position:absolute;top:60px;left:132px;width:24px;height:24px;pointer-events:none;opacity:0}\n  .gemmorph.done .sparkle{animation:tw 3.4s ease-in-out 1.5s infinite}\n  @keyframes tw{0%,100%{opacity:0;transform:scale(.3) rotate(0)}45%{opacity:.95;transform:scale(1) rotate(40deg)}62%{opacity:.25;transform:scale(.6) rotate(55deg)}}\n  @media(prefers-reduced-motion:reduce){\n    .pixgem{display:none}\n    .facetgem{opacity:1;transform:rotateY(-10deg) scale(1);animation:none}\n    .sparkle{display:none}\n  }\n</style>\n<style>\n  /* ===== genesis-specific ===== */\n  .gwrap{max-width:1000px;margin:0 auto;padding:0 28px}\n  .ghero{padding:58px 0 40px}\n  .ghero .gwrap{display:grid;grid-template-columns:1fr .8fr;gap:48px;align-items:center}\n  .ghero h1{font-family:var(--black);font-weight:900;font-size:clamp(34px,5.4vw,58px);line-height:.98;letter-spacing:-2px;margin:16px 0 0}\n  .ghero h1 .g{color:var(--gold)}\n  .ghero .sub{font-family:var(--serif);font-style:italic;color:var(--parch-dim);font-size:clamp(16px,2.2vw,20px);margin-top:18px;max-width:460px}\n  @media(max-width:840px){.ghero .gwrap{grid-template-columns:1fr;gap:34px}.gemstage{order:-1}}\n\n  .vest{margin-top:14px;border:1px solid var(--line);border-radius:6px;background:linear-gradient(180deg,var(--panel),var(--panel2));padding:30px}\n  .vmeta{display:flex;justify-content:space-between;flex-wrap:wrap;gap:10px;font-family:var(--mono);font-size:11px;letter-spacing:.12em;text-transform:uppercase;color:var(--ash);margin-bottom:22px}\n  .vmeta b{color:var(--gold);font-weight:400}\n  .days{display:flex;gap:10px;overflow-x:auto;padding-bottom:8px}\n  .day{flex:0 0 auto;width:88px;border:1px solid var(--line-soft);border-radius:5px;padding:11px;background:var(--raise)}\n  .day .dl{font-family:var(--mono);font-size:9px;letter-spacing:.08em;text-transform:uppercase;color:var(--ash);margin-bottom:9px}\n  .day .ds{display:grid;grid-template-columns:repeat(5,1fr);gap:3px}\n  .day .ds i{width:100%;aspect-ratio:1;border-radius:2px;box-shadow:inset 0 -1px 0 rgba(0,0,0,.35),inset 0 1px 0 rgba(255,255,255,.18)}\n  .day.more{display:flex;align-items:center;justify-content:center;color:var(--gold);font-family:var(--black);font-size:20px;min-width:54px;width:54px}\n  .day.fin{display:flex;flex-direction:column;justify-content:center;border-color:var(--line);background:rgba(227,169,62,.07)}\n  .day.fin .big{font-family:var(--black);color:var(--gold);font-size:17px;letter-spacing:-.5px}\n  .vnote{font-family:var(--mono);font-size:11px;color:var(--ash);margin-top:18px;line-height:1.7}\n  .vnote b{color:var(--parch-dim)}\n\n  .gsteps{display:grid;grid-template-columns:repeat(4,1fr);gap:16px;margin-top:30px}\n  .gstep{border:1px solid var(--line);border-radius:5px;padding:22px;background:var(--panel)}\n  .gstep .n{font-family:var(--black);font-size:12px;color:#1a1206;background:linear-gradient(145deg,var(--gold-hi),var(--gold-lo));width:28px;height:28px;border-radius:3px;display:flex;align-items:center;justify-content:center}\n  .gstep h4{font-size:15px;font-weight:800;margin:14px 0 7px}\n  .gstep p{font-size:13px;color:var(--parch-dim);line-height:1.5}\n  @media(max-width:820px){.gsteps{grid-template-columns:1fr 1fr}}\n  @media(max-width:460px){.gsteps{grid-template-columns:1fr}}\n\n  .guar{display:flex;flex-wrap:wrap;gap:10px;margin-top:26px}\n  .guar span{font-family:var(--mono);font-size:11px;letter-spacing:.08em;text-transform:uppercase;color:var(--parch-dim);border:1px solid var(--line);border-radius:2px;padding:9px 13px}\n  .guar span b{color:var(--gold);font-weight:400}\n</style>\n<style>nav.top{display:none!important}</style>\n</head>\n<body>\n\n<nav class=\"top\">\n  <div class=\"wrap\">\n    <div class=\"brand\"><span class=\"foil\">BRICK</span><span class=\"l\">Genesis</span></div>\n    <div class=\"navlinks\">\n      <a href=\"#\" onclick=\"parent.postMessage({brickNav:'whitepaper'},'*');return false;\">Whitepaper</a>\n      <a href=\"#\" onclick=\"parent.postMessage({brickNav:'launch'},'*');return false;\">Overview</a>\n      <a href=\"#mint\" class=\"live\">Genesis Live</a>\n    </div>\n  </div>\n</nav>\n\n<!-- HERO -->\n<header class=\"ghero\">\n  <div class=\"gwrap\">\n    <div class=\"rv in\">\n      <div class=\"kicker\">Genesis Formation \u00b7 HACD Labs Launchpad</div>\n      <h1>Claim a Lot.<br><span class=\"g\">Reveal Your Colors.</span></h1>\n      <p class=\"sub\">Genesis allocates the entire one-million-stone supply. Take a lot, and your stones release to you day by day \u2014 a daily draw of color.</p>\n      <div class=\"statstrip\">\n        <div class=\"s\"><div class=\"v\">1,000,000</div><div class=\"k\">Fixed Supply</div></div>\n        <div class=\"s\"><div class=\"v\">500</div><div class=\"k\">Genesis Slots</div></div>\n        <div class=\"s\"><div class=\"v\">0%</div><div class=\"k\">Team / VC</div></div>\n      </div>\n    </div>\n    <div class=\"gemstage rv in\">\n      <div class=\"pedestal\">\n        <div class=\"gemmorph\" id=\"gemmorph\">\n          <div class=\"pgrid pixgem\" id=\"gem\"></div>\n          <svg class=\"facetgem\" viewBox=\"0 0 200 220\" aria-label=\"Worked diamond\">\n            <defs>\n              <linearGradient id=\"gT\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\"><stop offset=\"0\" stop-color=\"#FBEFCB\"/><stop offset=\"1\" stop-color=\"#E3A93E\"/></linearGradient>\n              <linearGradient id=\"gB\" x1=\"0\" y1=\"0\" x2=\"1\" y2=\"1\"><stop offset=\"0\" stop-color=\"#F6DC9A\"/><stop offset=\"1\" stop-color=\"#C9912F\"/></linearGradient>\n              <linearGradient id=\"gM\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\"><stop offset=\"0\" stop-color=\"#E3A93E\"/><stop offset=\"1\" stop-color=\"#9A6E22\"/></linearGradient>\n              <linearGradient id=\"gD\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\"><stop offset=\"0\" stop-color=\"#B9822B\"/><stop offset=\"1\" stop-color=\"#6B4A15\"/></linearGradient>\n            </defs>\n            <g class=\"edge\">\n              <polygon points=\"70,22 130,22 140,72 60,72\" fill=\"url(#gT)\"/>\n              <polygon points=\"70,22 60,72 24,72\" fill=\"url(#gM)\"/>\n              <polygon points=\"130,22 176,72 140,72\" fill=\"url(#gB)\"/>\n              <polygon points=\"24,72 60,72 100,208\" fill=\"url(#gD)\"/>\n              <polygon points=\"60,72 100,72 100,208\" fill=\"url(#gB)\"/>\n              <polygon points=\"100,72 140,72 100,208\" fill=\"url(#gM)\"/>\n              <polygon points=\"140,72 176,72 100,208\" fill=\"url(#gD)\"/>\n              <polygon points=\"88,72 112,72 100,208\" fill=\"#FBEFCB\" opacity=\".5\"/>\n            </g>\n            <polygon points=\"78,28 116,28 110,40 84,40\" fill=\"#fff\" opacity=\".32\"/>\n            <line x1=\"24\" y1=\"72\" x2=\"176\" y2=\"72\" stroke=\"rgba(255,243,205,.45)\" stroke-width=\"1\"/>\n          </svg>\n          <svg class=\"sparkle\" viewBox=\"0 0 24 24\"><path d=\"M12 0 L14 10 L24 12 L14 14 L12 24 L10 14 L0 12 L10 10 Z\" fill=\"#fff\"/></svg>\n        </div>\n      </div>\n    </div>\n  </div>\n</header>\n\n<div class=\"course\"></div>\n\n<!-- MINT -->\n<section class=\"blk\" id=\"mint\">\n  <div class=\"gwrap rv\">\n    <div class=\"eyebrow\">Claim</div>\n    <h2>Mint Your <span class=\"o\">Genesis Lot</span></h2>\n    <div class=\"genesis\">\n      <div class=\"top\">\n        <div class=\"gx l\">\n          <div class=\"lab\">Per Slot</div>\n          <div class=\"price\">1 HACD + 30 HAC <small>/ slot</small></div>\n          <div class=\"getline\">Allocates <b>2,000 colored stones</b> \u2014 colors revealed <b>3 / day</b> post-launch.</div>\n          <ul class=\"glist\">\n            <li>Daily Color Reveal: 3 colors a day (post-launch feature)</li>\n            <li>Fixed supply 1,000,000 \u2014 the reveal never mints new BRICK</li>\n            <li>No team, private, or VC allocation \u00b7 no reserve</li>\n            <li>All 500 slots public</li>\n          </ul>\n        </div>\n        <div class=\"gx r\">\n          <div class=\"progwrap\">\n            <div class=\"progmeta\"><span>Slots claimed</span><span class=\"c\"><span id=\"claimed\">0</span> / 500</span></div>\n            <div class=\"track\"><div class=\"fill\" id=\"fill\"></div></div>\n          </div>\n          <a href=\"#\" class=\"btn primary\" id=\"mintbtn\">Connect &amp; Mint</a>\n          <div class=\"gnote\">Genesis runs on the HACD Labs Launchpad.<br>Participation is not an investment or guarantee of any kind.</div>\n        </div>\n      </div>\n      <div class=\"gbar\">\n        <span>Supply <b>1,000,000 \u00b7 Fixed</b></span>\n        <span>Per Slot <b>2,000 BRICK</b></span>\n        <span>Daily Reveal <b>3/day \u00b7 post-launch</b></span>\n        <span>Market <b>HAC \u00b7 2% Fee</b></span>\n      </div>\n    </div>\n  </div>\n</section>\n\n<div class=\"course\"></div>\n\n<!-- VESTING -->\n<section class=\"blk\">\n  <div class=\"gwrap rv\">\n    <div class=\"eyebrow\">Daily Color Reveal \u00b7 Post-Launch</div>\n    <h2>2,000 Stones, <span class=\"o\">Revealed 3 a Day</span></h2>\n    <p class=\"lead\">Your lot is allocated 2,000 stones at Genesis. The Daily Color Reveal \u2014 a planned post-launch BRICK product feature \u2014 then reveals their colors 3 a day, so every day is a small pack to open until all 2,000 are revealed in about 666 days.</p>\n    <div class=\"vest\">\n      <div class=\"vmeta\"><span>Daily reveal <b>3 stones</b></span><span>Full reveal <b>2,000 \u00b7 ~666 days</b></span><span>Then <b>reveal ends</b></span></div>\n      <div class=\"days\" id=\"days\"></div>\n      <div class=\"vnote\"><b>Colors above are illustrative</b> \u2014 each day's actual colors are drawn by chance from the rarity ladder. The reveal assigns colors to stones already allocated to your lot at Genesis; it never creates new BRICK. This is a post-launch BRICK product feature, not a Launchpad rule.</div>\n    </div>\n  </div>\n</section>\n\n<div class=\"course\"></div>\n\n<!-- HOW GENESIS WORKS -->\n<section class=\"blk\">\n  <div class=\"gwrap rv\">\n    <div class=\"eyebrow\">After You Claim</div>\n    <h2>From Lot <span class=\"o\">to Worked Diamond</span></h2>\n    <div class=\"gsteps\">\n      <div class=\"gstep\"><div class=\"n\">1</div><h4>Claim a lot</h4><p>Pay 1 HACD + 30 HAC. Your 2,000-stone allocation is recorded to your lot.</p></div>\n      <div class=\"gstep\"><div class=\"n\">2</div><h4>Reveal daily</h4><p>Post-launch, reveal 10 stones a day and see their colors. Build as they arrive, or buy more on the market.</p></div>\n      <div class=\"gstep\"><div class=\"n\">3</div><h4>Build on your HACD</h4><p>Set stones into a work modeled on a diamond you hold. Matching its palette is the rarest craft.</p></div>\n      <div class=\"gstep\"><div class=\"n\">4</div><h4>Keep, list, or dismantle</h4><p>Hold the worked diamond, sell it in HAC (2% fee), or break it back into stones to build again.</p></div>\n    </div>\n  </div>\n</section>\n\n<div class=\"course\"></div>\n\n<!-- PARAMETERS -->\n<section class=\"blk\">\n  <div class=\"gwrap rv\">\n    <div class=\"eyebrow\">Genesis Parameters</div>\n    <h2>The <span class=\"o\">Full Spec</span></h2>\n    <table>\n      <thead><tr><th>Parameter</th><th>Value</th></tr></thead>\n      <tbody>\n        <tr><td>Genesis Slots</td><td>500</td></tr>\n        <tr><td>Cost Per Slot</td><td><span class=\"o\">1 HACD + 30 HAC</span></td></tr>\n        <tr><td>BRICK Per Slot</td><td>2,000</td></tr>\n        <tr><td>Daily Color Reveal</td><td>3/day \u00b7 ~666 days \u00b7 post-launch</td></tr>\n        <tr><td>Stone Colors</td><td>Random \u2014 revealed daily (post-launch)</td></tr>\n        <tr><td>Participation</td><td>Open \u00b7 all 500 slots public</td></tr>\n        <tr><td>Team / Private / VC Allocation</td><td>None</td></tr>\n        <tr><td>Reserve</td><td>None</td></tr>\n        <tr><td>Further Minting</td><td>None</td></tr>\n        <tr class=\"tot\"><td>Total Supply (Fixed)</td><td>1,000,000 BRICK</td></tr>\n      </tbody>\n    </table>\n    <div class=\"guar\">\n      <span>Supply <b>Fixed forever</b></span>\n      <span>Minting <b>None</b></span>\n      <span>Team <b>0%</b></span>\n      <span>Slots <b>100% public</b></span>\n      <span>Reveal <b>\u2260 minting</b></span>\n    </div>\n  </div>\n</section>\n\n<!-- FOOTER -->\n<footer>\n  <div class=\"wrap\">\n    <div class=\"foot-grid\">\n      <div class=\"brand\"><span class=\"foil\">BRICK</span><span class=\"l\">Genesis</span></div>\n      <div class=\"foot-links\">\n        <a href=\"#\" onclick=\"parent.postMessage({brickNav:'whitepaper'},'*');return false;\">Whitepaper</a>\n        <a href=\"#\" onclick=\"parent.postMessage({brickNav:'launch'},'*');return false;\">Overview</a>\n        <a href=\"https://x.com/protocolbrick\" target=\"_blank\" rel=\"noreferrer\">X / Twitter</a>\n        <a href=\"https://t.me/protocolbrick\" target=\"_blank\" rel=\"noreferrer\">Telegram</a>\n      </div>\n    </div>\n    <div class=\"addr\"><b>Genesis HAC receiving address</b><br><code>19UWYeDC4DnQQGJoXvykBGp1WUnVUtcUVu</code></div>\n    <div class=\"disc\">\n      <span class=\"em\">DISCLAIMER</span> \u2014 This page describes BRICK Protocol's Genesis Formation for informational purposes only. It is not investment advice, an offer, or a solicitation. BRICK is a fixed-supply utility asset for producing works; it is not a security, carries no claim or dividend, and the protocol makes no promise of profit, income, or return. The Daily Color Reveal assigns colors to stones already allocated at Genesis and never mints new BRICK; it is a planned post-launch product feature. Participation does not constitute an investment or guarantee of any kind. Features remain subject to development and implementation.<br><br>\n      BRICK Protocol \u00b7 Genesis Formation \u00b7 HACD Native \u00b7 Launch on HACD Labs \u00b7 0% Team Allocation\n    </div>\n  </div>\n</footer>\n\n<script>\n// cover gem: build \u2192 3D faceted diamond\nconst GEM=[\n\"0000111111110000\",\"0001111111111000\",\"0011111111111100\",\"0111111111111110\",\n\"1111111111111111\",\"0111111111111110\",\"0011111111111100\",\"0011111111111100\",\n\"0001111111111000\",\"0001111111111000\",\"0000111111110000\",\"0000011111100000\",\n\"0000011111100000\",\"0000001111000000\",\"0000000110000000\",\"0000000110000000\"];\n(function(){\n  const g=document.getElementById('gem');\n  g.style.gridTemplateColumns='repeat(16,13px)';g.style.gridTemplateRows='repeat(16,13px)';\n  const reduce=window.matchMedia('(prefers-reduced-motion: reduce)').matches;\n  GEM.forEach((row,r)=>{[...row].forEach(ch=>{\n    const d=document.createElement('div');d.className='pc'+(ch==='1'?' on':'');\n    if(ch==='1'&&!reduce){d.style.animationDelay=(r*52+Math.random()*40)+'ms';}\n    g.appendChild(d);});});\n  if(!reduce){const m=document.getElementById('gemmorph');setTimeout(()=>m.classList.add('done'),1500);}\n})();\n\n// 16 colors weighted by rarity share\nconst COLORS=[\n [\"#E0303A\",\"2.0\"],[\"#2FB46A\",\"2.5\"],[\"#2D6BE0\",\"3.0\"],[\"#7A3FE0\",\"3.5\"],\n [\"#E85FA8\",\"4.0\"],[\"#E8842A\",\"4.5\"],[\"#2FC4CF\",\"5.0\"],[\"#E8C53A\",\"5.5\"],\n [\"#2E9E8F\",\"6.5\"],[\"#C24FD1\",\"7.0\"],[\"#8FC73A\",\"7.5\"],[\"#4256C8\",\"8.0\"],\n [\"#6E7A8A\",\"9.0\"],[\"#9A6A3A\",\"9.5\"],[\"#9098A0\",\"10.0\"],[\"#D8D2C4\",\"12.5\"]];\nconst pool=[];COLORS.forEach(c=>{const n=Math.round(parseFloat(c[1])*4);for(let i=0;i<n;i++)pool.push(c[0]);});\nfunction rndCol(){return pool[Math.floor(Math.random()*pool.length)];}\n\n// daily vesting reveal (first days + finale)\n(function(){\n  const wrap=document.getElementById('days');\n  for(let d=1;d<=5;d++){\n    const card=document.createElement('div');card.className='day';\n    let s='';for(let i=0;i<3;i++)s+=`<i style=\"background:linear-gradient(145deg,${rndCol()},rgba(0,0,0,.45))\"></i>`;\n    card.innerHTML=`<div class=\"dl\">Day ${d} \u00b7 +3</div><div class=\"ds\">${s}</div>`;\n    wrap.appendChild(card);\n  }\n  const more=document.createElement('div');more.className='day more';more.textContent='\u00b7\u00b7\u00b7';wrap.appendChild(more);\n  const fin=document.createElement('div');fin.className='day fin';fin.innerHTML=`<div class=\"dl\">Day 666</div><div class=\"big\">2,000 \u2713</div>`;wrap.appendChild(fin);\n})();\n\n// slots progress (team wires the real number)\nconst CLAIMED=0,TOTAL=500;\nwindow.addEventListener('load',()=>{\n  document.getElementById('claimed').textContent=CLAIMED;\n  setTimeout(()=>{const f=document.getElementById('fill');if(f)f.style.width=(CLAIMED/TOTAL*100)+'%';},300);\n});\n\n// scroll reveal\nconst io=new IntersectionObserver((es)=>{es.forEach(e=>{if(e.isIntersecting){e.target.classList.add('in');io.unobserve(e.target);}});},{threshold:.12});\ndocument.querySelectorAll('.rv:not(.in)').forEach(el=>io.observe(el));\n</script>\n</body>\n</html>\n"
};

PAGES.launch = PAGES.launch.replace(
  `<div class="navlinks">\n      <a href="#" onclick="parent.postMessage({brickNav:'whitepaper'},'*');return false;">Whitepaper</a>\n      <a href="#how">How it works</a>\n      <a href="#stones">Stones</a>\n      <a href="#" onclick="parent.postMessage({brickNav:'genesis'},'*');return false;" class="live">Genesis Live</a>\n    </div>`,
  `<div class="navlinks">\n      <a href="#" onclick="parent.postMessage({brickNav:'whitepaper'},'*');return false;">Whitepaper</a>\n      <a href="#how">How it works</a>\n      <a href="#stones">Stones</a>\n      <button type="button" class="live" onclick="parent.postMessage({brickNav:'dashboard'},'*');return false;" style="background:transparent;appearance:none;-webkit-appearance:none;">BUILD</button>\n      <a href="#" onclick="parent.postMessage({brickNav:'genesis'},'*');return false;" class="live">Genesis Live</a>\n    </div>`
);

PAGES.genesis = PAGES.genesis.replace('reveal 10 stones a day', 'reveal 3 stones a day');

PAGES.dashboard = `<!doctype html>
<html lang="tr">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>BRICK Protocol — Dashboard</title>
<style>
  html,body{margin:0;width:100%;height:100%;overflow:hidden;background:#0A0D12}
  iframe{display:block;width:100%;height:100%;border:0;background:#0A0D12}
</style>
</head>
<body>
  <iframe src="dashboard/index.html" title="BRICK Dashboard"></iframe>
</body>
</html>`;

PAGES.launch = PAGES.launch.replace('>BUILD</button>', '>BUILD NOW</button>');

const ROUTES=['launch','whitepaper','genesis','dashboard'];
const wrap=document.getElementById('frames');
const frames={};
ROUTES.forEach(function(r){
  var f=document.createElement('iframe');
  f.className='page'; f.setAttribute('title',r); f.srcdoc=PAGES[r];
  wrap.appendChild(f); frames[r]=f;
});
function show(r){
  if(ROUTES.indexOf(r)<0) r='launch';
  ROUTES.forEach(function(k){ frames[k].classList.toggle('on', k===r); });
  var links=document.querySelectorAll('.shnav .links a');
  for(var i=0;i<links.length;i++){ links[i].classList.toggle('active', links[i].getAttribute('data-r')===r); }
  document.title='BRICK Protocol - '+r.charAt(0).toUpperCase()+r.slice(1);
}
function fromHash(){ var m=location.hash.match(/^#\/(\w+)/); return m?m[1]:'launch'; }
window.addEventListener('hashchange',function(){ show(fromHash()); });
window.addEventListener('message',function(e){ if(e.data&&e.data.brickNav){ location.hash='#/'+e.data.brickNav; } });
show(fromHash());
